                {/* ── IG POSTS PANEL ── */}
                {tab === 'igposts' && (
                  <div className="space-y-12">
                    {ARTIST_META.map(a => {
                      const posts = igPosts[a.value] ?? [];
                      if (posts.length === 0) return null;
                      const totalEmv = posts.reduce((s, p) => s + Number(p.emv), 0);
                      
                      return (
