'use client';

import { useState, useRef, useEffect, useMemo } from 'react';
import Image from 'next/image';
import { motion, AnimatePresence } from 'framer-motion';
import { Header } from '@/components/navigation/Header';
import { ArrowLeft, Clock, History, Star, Award, Tv, Megaphone, Milestone } from 'lucide-react';
import { Link } from '@/i18n/routing';
import { TimelineEvent } from '@/data/timeline';
import { cn } from '@/lib/utils';

const CATEGORY_CONFIG: Record<string, { label: string; icon: unknown; color: string; labelTh: string }> = {
  all:       { label: 'All Events', icon: History, color: 'var(--primary)', labelTh: 'ทั้งหมด' },
  milestone: { label: 'Milestones', icon: Milestone, color: '#A78BFA', labelTh: 'เหตุการณ์สำคัญ' },
  work:      { label: 'Projects',   icon: Tv, color: 'var(--namtan-teal)', labelTh: 'ผลงาน' },
  award:     { label: 'Awards',     icon: Award, color: 'var(--film-gold)', labelTh: 'รางวัล' },
  event:     { label: 'Publicity',  icon: Megaphone, color: '#EF5350', labelTh: 'กิจกรรม' },
  debut:     { label: 'Debut',      icon: Star, color: '#66BB6A', labelTh: 'เดบิวต์' },
};

export default function TimelinePage() {
  const [allEvents, setAllEvents] = useState<TimelineEvent[]>([]);
  const [loadingEvents, setLoadingEvents] = useState(true);
  const [actorFilter, setActorFilter] = useState<'all' | 'namtan' | 'film' | 'both'>('all');
  const [categoryFilter, setCategoryFilter] = useState<string>('all');
  const [activeYear, setActiveYear] = useState<number | null>(null);
  const yearRefs = useRef<Record<number, HTMLDivElement | null>>({});
  const [isMobile, setIsMobile] = useState(false);

  useEffect(() => {
    fetch('/api/timeline')
      .then(r => r.json())
      .then(data => {
        if (Array.isArray(data)) {
          setAllEvents(data.map((row: unknown) => ({ ...row, titleThai: row.title_thai ?? '' })));
        }
      })
      .catch(console.error)
      .finally(() => setLoadingEvents(false));
      
    const check = () => setIsMobile(window.innerWidth < 768);
    check();
    window.addEventListener('resize', check);
    return () => window.removeEventListener('resize', check);
  }, []);

  const events = useMemo(() => {
    let filtered = allEvents;
    if (actorFilter === 'both') {
      filtered = allEvents.filter(e => e.actor === 'both');
    } else if (actorFilter === 'namtan' || actorFilter === 'film') {
      filtered = allEvents.filter(e => e.actor === actorFilter || e.actor === 'both');
    }
    if (categoryFilter !== 'all') {
      filtered = filtered.filter(e => e.category === categoryFilter);
    }
    return filtered;
  }, [allEvents, actorFilter, categoryFilter]);

  const grouped = useMemo(() => {
    return events.reduce((acc, ev) => {
      if (!acc[ev.year]) acc[ev.year] = [];
      acc[ev.year].push(ev);
      return acc;
    }, {} as Record<number, TimelineEvent[]>);
  }, [events]);

  const years = Object.keys(grouped).map(Number).sort((a, b) => b - a); // Newest first for better magazine reading

  useEffect(() => {
    if (years.length > 0 && activeYear === null) {
      setActiveYear(years[0]);
    }
  }, [years, activeYear]);

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach((entry) => {
          if (entry.isIntersecting) {
            const year = Number(entry.target.getAttribute('data-year'));
            if (year) setActiveYear(year);
          }
        });
      },
      { rootMargin: '-30% 0px -60% 0px' }
    );
    Object.values(yearRefs.current).forEach((el) => { if (el) observer.observe(el); });
    return () => observer.disconnect();
  }, [events]);

  const scrollToYear = (year: number) => {
    const el = yearRefs.current[year];
    if (el) {
      const offset = 140;
      const top = el.getBoundingClientRect().top + window.scrollY - offset;
      window.scrollTo({ top, behavior: 'smooth' });
      setActiveYear(year);
    }
  };

  if (loadingEvents) {
    return (
      <div className="min-h-screen bg-[var(--color-bg)] flex flex-col items-center justify-center gap-6">
        <div className="w-12 h-12 rounded-full border-2 border-theme border-t-accent animate-spin" />
        <p className="text-[10px] font-bold uppercase tracking-[0.3em] text-muted animate-pulse">Building Timeline...</p>
      </div>
    );
  }

  return (
    <main className="min-h-screen bg-[var(--color-bg)] transition-colors duration-500 relative">
      <Header />
      
      <div className="pt-32 pb-24 container mx-auto px-6 md:px-12 lg:px-20 max-w-7xl">
        
        {/* Header Section */}
        <header className="mb-16">
          <Link href="/" className="inline-flex items-center gap-2 text-muted hover:text-accent transition-all mb-8 text-[10px] font-bold uppercase tracking-[0.3em] group">
            <ArrowLeft className="w-3 h-3 group-hover:-translate-x-1 transition-transform" />
            Back to Home
          </Link>
          
          <div className="flex flex-col md:flex-row md:items-end justify-between gap-8 border-b border-theme/40 pb-12">
            <div>
              <p className="text-overline text-accent font-bold mb-4 uppercase tracking-[0.4em]">Historical Journey</p>
              <h1 className="text-5xl md:text-7xl font-display text-primary leading-tight font-light">
                Memorial <span className="nf-gradient-text italic">Chronicles</span>
              </h1>
            </div>
            <div className="flex flex-col gap-6 max-w-sm">
               <p className="text-muted text-sm leading-relaxed font-body opacity-80">
                  Tracing the significant milestones, works, and awards that define the legacy of Namtan and Film.
               </p>
               {/* Year Pills Navigation */}
               <div className="flex flex-wrap gap-2">
                  {years.map(y => (
                    <button key={y} onClick={() => scrollToYear(y)} 
                      className={cn("px-4 py-1.5 rounded-full text-[10px] font-bold uppercase tracking-widest border transition-all duration-300", 
                      activeYear === y ? "bg-deep-dark text-white border-deep-dark shadow-md" : "bg-panel border-theme/40 text-muted hover:border-accent hover:text-accent")}>
                      {y}
                    </button>
                  ))}
               </div>
            </div>
          </div>
        </header>

        {/* Global Filters */}
        <div className="sticky top-20 z-30 bg-[var(--color-bg)]/80 backdrop-blur-xl py-6 mb-16 border-b border-theme/20">
           <div className="flex flex-col lg:flex-row gap-8 items-center justify-between">
              <div className="flex p-1 bg-surface border border-theme/60 rounded-full shadow-sm">
                {[
                  { id: 'all', label: 'All' },
                  { id: 'both', label: 'Together' },
                  { id: 'namtan', label: 'Namtan' },
                  { id: 'film', label: 'Film' },
                ].map(f => (
                  <button
                    key={f.id}
                    onClick={() => setActorFilter(f.id as unknown)}
                    className={cn(
                      "px-6 py-2 rounded-full text-[10px] font-bold uppercase tracking-widest transition-all duration-300",
                      actorFilter === f.id ? "bg-primary text-deep-dark shadow-md" : "text-muted hover:text-primary"
                    )}
                  >
                    {f.label}
                  </button>
                ))}
              </div>

              <div className="flex flex-wrap justify-center gap-3">
                {Object.entries(CATEGORY_CONFIG).map(([key, config]) => {
                  const active = categoryFilter === key;
                  if (key === 'all') return null;
                  const count = events.filter(e => e.category === key).length;
                  if (count === 0 && !active) return null;
                  
                  return (
                    <button
                      key={key}
                      onClick={() => setCategoryFilter(active ? 'all' : key)}
                      className={cn(
                        "flex items-center gap-2 px-5 py-2 rounded-full text-[10px] font-bold uppercase tracking-widest border transition-all duration-300",
                        active ? "bg-deep-dark text-white border-deep-dark shadow-lg" : "bg-surface text-muted border-theme hover:border-accent hover:text-accent"
                      )}
                    >
                      <config.icon className="w-3 h-3" />
                      {config.label}
                    </button>
                  );
                })}
              </div>
           </div>
        </div>

        {/* Timeline Feed */}
        <div className="relative max-w-5xl mx-auto">
           {/* Center line (Desktop) */}
           <div className="absolute left-[30px] md:left-1/2 top-4 bottom-0 w-px bg-gradient-to-b from-theme via-theme to-transparent md:-translate-x-1/2 opacity-40" />

           <AnimatePresence mode="popLayout">
              {years.length === 0 ? (
                <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="text-center py-32 opacity-40">
                   <Clock className="w-16 h-16 mx-auto mb-6 grayscale" />
                   <p className="text-sm font-bold uppercase tracking-widest">No history found for these filters</p>
                </motion.div>
              ) : (
                years.map(year => (
                  <div key={year} className="mb-24 relative" ref={el => { yearRefs.current[year] = el; }} data-year={year}>
                    {/* Year Indicator */}
                    <div className="sticky top-44 z-20 mb-12 flex md:justify-center">
                       <span className="px-8 py-3 bg-deep-dark text-white rounded-full text-2xl font-display font-light tracking-[0.2em] shadow-2xl">
                          {year}
                       </span>
                    </div>

                    <div className="space-y-16">
                       {grouped[year].map((ev, i) => {
                         const isLeft = i % 2 === 0;
                         const config = CATEGORY_CONFIG[ev.category] || CATEGORY_CONFIG.milestone;
                         
                         return (
                           <motion.div
                              key={ev.id}
                              initial={{ opacity: 0, y: 30 }}
                              whileInView={{ opacity: 1, y: 0 }}
                              viewport={{ once: true, margin: "-100px" }}
                              transition={{ duration: 0.7, ease: [0.22, 1, 0.36, 1], delay: i * 0.05 }}
                              className={cn("relative flex items-center gap-12 md:gap-20", isLeft ? "md:flex-row" : "md:flex-row-reverse")}
                           >
                              {/* Connector Dot */}
                              <div className="absolute left-[30px] md:left-1/2 w-4 h-4 rounded-full border-4 border-[var(--color-bg)] bg-accent z-10 shadow-lg md:-translate-x-1/2" />

                              {/* Card Content */}
                              <div className={cn("flex-1 pl-16 md:pl-0", isLeft ? "md:text-right" : "md:text-left")}>
                                 <div className={cn("group bg-surface border border-theme/60 rounded-[2rem] p-8 md:p-10 hover:shadow-2xl hover:border-accent/40 transition-all duration-500 relative overflow-hidden inline-block w-full max-w-xl", isLeft ? "md:ml-auto" : "md:mr-auto")}>
                                    <div className="absolute top-0 left-0 w-1 h-full opacity-10 group-hover:opacity-100 transition-opacity" style={{ background: config.color }} />
                                    
                                    <div className={cn("flex items-center gap-4 mb-6", isLeft ? "md:justify-end" : "md:justify-start")}>
                                       <div className="p-2.5 rounded-xl bg-panel border border-theme/40 text-muted grayscale-[0.5] group-hover:grayscale-0 transition-all duration-500">
                                          <config.icon className="w-5 h-5" />
                                       </div>
                                       <span className="text-[9px] font-bold uppercase tracking-[0.25em] px-3 py-1 rounded-full border border-theme/40" style={{ background: `${config.color}10`, color: config.color }}>
                                          {config.label}
                                       </span>
                                    </div>

                                    <h3 className="text-xl md:text-2xl font-display text-primary leading-tight font-light mb-4 group-hover:text-accent transition-colors">
                                       {ev.titleThai || ev.title}
                                    </h3>
                                    
                                    <p className="text-muted text-sm md:text-base leading-relaxed font-body opacity-80 mb-8">
                                       {ev.description}
                                    </p>

                                    {ev.image && (
                                       <div className="relative aspect-video rounded-2xl overflow-hidden bg-panel mb-8 border border-theme/40">
                                          <Image src={ev.image} alt="" fill className="object-cover transition-all duration-1000 group-hover:scale-110 grayscale-[0.2] group-hover:grayscale-0" />
                                          <div className="absolute inset-0 bg-gradient-to-t from-deep-dark/40 to-transparent" />
                                       </div>
                                    )}

                                    <div className={cn("flex items-center gap-3", isLeft ? "md:justify-end" : "md:justify-start")}>
                                       <div className="flex -space-x-1">
                                          {ev.actor === 'both' ? (
                                            <>
                                               <div className="w-2.5 h-2.5 rounded-full bg-namtan-teal border border-surface shadow-sm" />
                                               <div className="w-2.5 h-2.5 rounded-full bg-film-gold border border-surface shadow-sm" />
                                            </>
                                          ) : (
                                            <div className="w-2.5 h-2.5 rounded-full border border-surface shadow-sm" style={{ background: ev.actor === 'namtan' ? 'var(--namtan-teal)' : 'var(--film-gold)' }} />
                                          )}
                                       </div>
                                       <span className="text-[9px] font-bold uppercase tracking-widest text-muted/40">
                                          {ev.actor === 'both' ? 'Together' : ev.actor}
                                       </span>
                                    </div>
                                 </div>
                              </div>

                              {/* Empty side for layout spacing */}
                              <div className="hidden md:block flex-1" />
                           </motion.div>
                         );
                       })}
                    </div>
                  </div>
                ))
              )}
           </AnimatePresence>
        </div>

      </div>
    </main>
  );
}

import { notFound } from 'next/navigation';
import Link from 'next/link';
import Image from 'next/image';
import { ArrowLeft, PlayCircle, ExternalLink, Calendar, Users, Info, Film } from 'lucide-react';
import { getAdminClient } from '@/lib/supabase';
import { Header } from '@/components/navigation/Header';
import { Footer } from '@/components/ui/Footer';
import { cn } from '@/lib/utils';

export const revalidate = 60;

export default async function WorkDetailPage({ params }: { params: Promise<{ id: string }> }) {
  const { id } = await params;
  const supabase = getAdminClient();
  
  const { data: item, error } = await supabase
    .from('content_items')
    .select('*')
    .eq('id', id)
    .eq('visible', true)
    .single();

  if (error || !item) {
    notFound();
  }

  let links: unknown[] = [];
  try {
    if (item.links) {
      links = typeof item.links === 'string' ? JSON.parse(item.links) : item.links;
    }
  } catch (e) {}

  const trailerLink = links.find((l: unknown) => l.platform?.toLowerCase() === 'youtube' || l.url?.includes('youtube.com/watch'));
  const getYouTubeId = (url: string) => {
    if (!url || (!url.includes('youtube.com') && !url.includes('youtu.be'))) return null;
    const regExp = /^.*(youtu.be\/|v\/|u\/\w\/|embed\/|watch\?v=|\&v=)([^#\&\?]*).*/;
    const match = url.match(regExp);
    return (match && match[2].length === 11) ? match[2] : null;
  };
  const trailerId = trailerLink ? getYouTubeId(trailerLink.url) : null;

  return (
    <main className="min-h-screen bg-[var(--color-bg)] transition-colors duration-500">
      <Header />
      
      {/* Hero Header Section */}
      <div className="relative h-[65vh] md:h-[80vh] w-full overflow-hidden bg-panel">
        {item.image ? (
          <Image 
            src={item.image} 
            alt={item.title} 
            fill
            priority
            sizes="100vw"
            className="object-cover opacity-30 grayscale-[0.3]"
          />
        ) : (
          <div className="w-full h-full bg-panel flex items-center justify-center">
             <Film className="w-24 h-24 text-muted opacity-10" />
          </div>
        )}
        
        {/* Soft Magazine Gradient */}
        <div className="absolute inset-0 bg-gradient-to-t from-[var(--color-bg)] via-[var(--color-bg)]/40 to-transparent"></div>
        
        <div className="absolute bottom-0 left-0 right-0 p-8 md:p-16 lg:p-24 z-10 w-full max-w-7xl mx-auto">
          <Link href="/works" className="inline-flex items-center gap-2 text-muted hover:text-accent transition-all mb-10 text-[10px] font-bold uppercase tracking-[0.3em] group">
            <ArrowLeft className="w-3 h-3 group-hover:-translate-x-1 transition-transform" />
            Back to Archive
          </Link>

          <div className="flex flex-col md:flex-row gap-12 md:items-end">
            {/* Poster Card */}
            <div className="hidden md:block relative w-72 shrink-0 rounded-[2.5rem] overflow-hidden border border-theme shadow-2xl bg-surface aspect-[2/3] group hover:scale-[1.02] transition-transform duration-700">
              {item.image && (
                <Image src={item.image} alt={item.title} fill sizes="288px" className="object-cover group-hover:scale-110 transition-transform duration-1000" />
              )}
            </div>

            {/* Title & Metadata */}
            <div className="flex-1 pb-4">
              <div className="flex flex-wrap items-center gap-4 mb-8">
                <span className="px-4 py-1 bg-accent text-deep-dark rounded-full text-[10px] font-bold uppercase tracking-[0.2em] shadow-sm">
                  {item.content_type}
                </span>
                <span className="flex items-center gap-2 text-muted text-xs font-bold uppercase tracking-widest">
                  <Calendar className="w-4 h-4 opacity-40" /> {item.year}
                </span>
                <div className="flex -space-x-1 ml-4">
                  {item.actors?.includes('namtan') && <div className="w-3 h-3 rounded-full bg-namtan-primary border-2 border-[var(--color-bg)]" />}
                  {item.actors?.includes('film') && <div className="w-3 h-3 rounded-full bg-film-primary border-2 border-[var(--color-bg)]" />}
                </div>
              </div>
              
              <h1 className="text-5xl md:text-7xl font-display text-primary leading-tight font-light mb-4 max-w-4xl">
                {item.title}
              </h1>
              {item.title_thai && (
                <h2 className="text-2xl md:text-3xl text-muted font-thai font-light tracking-wide mb-10 opacity-70">
                  {item.title_thai}
                </h2>
              )}

              {/* Action Toolbar */}
              <div className="flex flex-wrap items-center gap-4">
                {trailerLink && (
                  <a href="#trailer" className="inline-flex items-center gap-3 bg-deep-dark text-white px-8 py-4 rounded-full text-[10px] font-bold uppercase tracking-[0.25em] hover:bg-accent hover:text-deep-dark transition-all duration-300 shadow-xl">
                    <PlayCircle className="w-4 h-4" />
                    Watch Trailer
                  </a>
                )}
                {links.filter((l: unknown) => l.platform?.toLowerCase() !== 'youtube' && !l.url?.includes('youtube.com/watch')).map((link: unknown, idx: number) => (
                  <a 
                    key={idx} 
                    href={link.url} 
                    target="_blank" 
                    rel="noreferrer"
                    className="inline-flex items-center gap-3 bg-surface text-primary px-8 py-4 rounded-full text-[10px] font-bold uppercase tracking-[0.25em] border border-theme hover:border-accent transition-all duration-300 shadow-sm"
                  >
                    View on {link.platform}
                    <ExternalLink className="w-3 h-3 opacity-40" />
                  </a>
                ))}
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Main Content Body */}
      <div className="max-w-7xl mx-auto px-8 md:px-16 lg:px-24 py-24 grid grid-cols-1 lg:grid-cols-3 gap-20">
        
        {/* Left Column: Description & Media */}
        <div className="lg:col-span-2 space-y-24">
          
          {/* Synopsis Section */}
          <section className="relative">
            <div className="absolute -left-12 top-0 w-1 h-full bg-gradient-to-b from-accent to-transparent opacity-20 hidden md:block" />
            <h3 className="text-overline text-accent font-bold mb-8 uppercase tracking-[0.4em]">Synopsis</h3>
            <div className="text-primary/90 text-lg md:text-xl leading-relaxed font-body whitespace-pre-wrap">
              {item.description || 'No detailed description recorded for this entry.'}
            </div>
          </section>

          {/* Trailer Section */}
          {trailerId && (
            <section id="trailer" className="scroll-mt-32">
              <h3 className="text-overline text-accent font-bold mb-8 uppercase tracking-[0.4em]">Official Video</h3>
              <div className="aspect-video w-full rounded-[3rem] overflow-hidden border border-theme shadow-2xl bg-deep-dark relative group">
                <iframe 
                  width="100%" 
                  height="100%" 
                  src={`https://www.youtube.com/embed/${trailerId}?rel=0&showinfo=0`} 
                  title="Official Trailer" 
                  frameBorder="0" 
                  allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture" 
                  allowFullScreen
                  className="opacity-90 group-hover:opacity-100 transition-opacity duration-700"
                ></iframe>
              </div>
            </section>
          )}
        </div>

        {/* Right Column: Metadata Sidebar */}
        <aside className="space-y-12">
          <div className="bg-surface border border-theme/60 rounded-[2.5rem] p-10 shadow-sm sticky top-32">
            <h3 className="text-[10px] font-bold text-muted uppercase tracking-[0.3em] mb-10 border-b border-theme/40 pb-4">
              Project Intelligence
            </h3>
            
            <div className="space-y-8">
              {[
                { label: 'Role / Character', value: item.role },
                { label: 'Platform / Channel', value: item.event_type },
                { label: 'Venue / Location', value: item.venue },
                { label: 'Release Date', value: item.date },
                { label: 'Magazine / Issue', value: item.magazine_name ? `${item.magazine_name} ${item.issue ? `(${item.issue})` : ''}` : null },
                { label: 'Award Category', value: item.award_name },
              ].map((row, i) => row.value && (
                <div key={i} className="group/meta">
                  <dt className="text-[9px] font-bold text-muted uppercase tracking-[0.2em] mb-2 opacity-50 group-hover/meta:opacity-100 transition-opacity">
                    {row.label}
                  </dt>
                  <dd className="text-primary text-base font-body font-medium">{row.value}</dd>
                </div>
              ))}
              
              {item.link && (
                <div className="pt-8 mt-8 border-t border-theme/40">
                  <a href={item.link} target="_blank" rel="noreferrer" className="inline-flex items-center gap-3 text-[10px] font-bold uppercase tracking-[0.2em] text-accent hover:underline">
                    Access Official Resource <ExternalLink className="w-3 h-3" />
                  </a>
                </div>
              )}
            </div>
          </div>
        </aside>
      </div>

      <Footer />
    </main>
  );
}

