  accent_color: string;
}

const DEFAULT_CONFIGS: BannerConfig[] = [
  { slug: 'both', title: 'Namtan × Film', title_thai: 'น้ำตาล × ฟิล์ม', tagline: 'Together, Always', tagline_thai: 'คู่กันตลอดไป', banner_image: '/images/banners/banner.png', accent_color: 'teal' },
