  { slug: 'film', title: 'Film Rachanun', title_thai: 'ฟิล์ม รชานันท์', tagline: 'Rising Star with Versatile Talent', tagline_thai: 'ดาวรุ่งพุ่งแรงแห่ง GMMTV', banner_image: '/images/banners/f.png', accent_color: 'gold' },
