'use client';

import { useState, useEffect, useRef, useCallback } from 'react';
import Image from 'next/image';
import Link from 'next/link';
import type { HeroSlide } from '@/components/hero/HeroSlider';
import type { HeroBannerConfig } from '@/lib/homepage-data';

const BLANK: Omit<HeroSlide, 'id'> = {
  title: '',
  title_thai: '',
  subtitle: '',
  subtitle_thai: '',
  image: '',
  link: '',
  sort_order: 0,
  enabled: true,
  theme: 'both',
  view_state: 'both',
};

const THEME_OPTIONS = [
  { value: 'both' as const,  label: '☀️🌙 ทั้งคู่',  cls: 'bg-[var(--color-accent)]/15 border-[var(--color-accent)] text-[var(--color-accent)]' },
  { value: 'light' as const, label: '☀️ Light', cls: 'bg-amber-500/15 border-amber-500/50 text-amber-600' },
  { value: 'dark' as const,  label: '🌙 Dark',  cls: 'bg-indigo-500/15 border-indigo-500/50 text-indigo-400' },
];

function themeBadge(theme: HeroSlide['theme']) {
  if (theme === 'light') return { label: '☀️ Light', cls: 'bg-amber-500/10 border-amber-500/30 text-amber-600' };
  if (theme === 'dark')  return { label: '🌙 Dark',  cls: 'bg-indigo-500/10 border-indigo-500/30 text-indigo-400' };
  return { label: '☀️🌙 Both', cls: 'bg-[var(--color-panel)] border-[var(--color-border)] text-[var(--color-text-muted)]' };
}

const VIEW_STATE_OPTIONS = [
  { value: 'both' as const,   label: '👥 ทั้งหมด',  cls: 'bg-[var(--color-accent)]/15 border-[var(--color-accent)] text-[var(--color-accent)]' },
  { value: 'namtan' as const, label: '💜 Namtan', cls: 'bg-purple-500/15 border-purple-500/50 text-purple-500' },
  { value: 'film' as const,   label: '💙 Film',   cls: 'bg-blue-500/15 border-blue-500/50 text-blue-500' },
  { value: 'lunar' as const,  label: '🌙 Lunar',  cls: 'bg-pink-500/15 border-pink-500/50 text-pink-500' },
];

function viewStateBadge(vs: HeroSlide['view_state']) {
  if (vs === 'namtan') return { label: '💜 Namtan', cls: 'bg-purple-500/10 border-purple-500/30 text-purple-500' };
  if (vs === 'film')   return { label: '💙 Film',   cls: 'bg-blue-500/10 border-blue-500/30 text-blue-500' };
  if (vs === 'lunar')  return { label: '🌙 Lunar',  cls: 'bg-pink-500/10 border-pink-500/30 text-pink-500' };
  return { label: '👥 All', cls: 'bg-[var(--color-panel)] border-[var(--color-border)] text-[var(--color-text-muted)]' };
}

export default function HeroSlidesAdminPage() {
  const [slides, setSlides]           = useState<HeroSlide[]>([]);
  const [loading, setLoading]         = useState(true);
  const [editing, setEditing]         = useState<HeroSlide | null>(null);
  const [isNew, setIsNew]             = useState(false);
  const [saving, setSaving]           = useState(false);
  const [uploadPct, setUploadPct]     = useState<number | null>(null);
  const [toast, setToast]             = useState<{ msg: string; ok: boolean } | null>(null);
  const [themeFilter, setThemeFilter] = useState<'all' | 'light' | 'dark'>('all');
  const [activeTab, setActiveTab]     = useState<'banner' | 'slides'>('banner');
  const [bannerConfig, setBannerConfig] = useState<HeroBannerConfig>({ type: 'cinematic', showScrollHint: true });
  const [savingBanner, setSavingBanner] = useState(false);
  const fileRef = useRef<HTMLInputElement>(null);

  const showToast = useCallback((msg: string, ok = true) => {
    setToast({ msg, ok });
    setTimeout(() => setToast(null), 4000);
  }, []);

  const load = useCallback(async () => {
    setLoading(true);
    try {
      const [slidesRes, settingsRes] = await Promise.all([
        fetch('/api/admin/hero-slides', { cache: 'no-store' }),
        fetch('/api/admin/settings', { cache: 'no-store' })
      ]);
      if (!slidesRes.ok || !settingsRes.ok) throw new Error('HTTP Error');
      const slidesData = await slidesRes.json();
      const settingsData = await settingsRes.json();
      setSlides(Array.isArray(slidesData) ? slidesData : []);
      setBannerConfig(settingsData.heroBanner || { type: 'cinematic', showScrollHint: true });
    } catch (e) {
      showToast(`โหลดข้อมูลไม่สำเร็จ: ${e instanceof Error ? e.message : 'unknown'}`, false);
    } finally {
      setLoading(false);
    }
  }, [showToast]);

  useEffect(() => { load(); }, [load]);

  const openNew = (template: Omit<HeroSlide, 'id'> = BLANK) => {
    setIsNew(true);
    setEditing({ id: '', ...template, sort_order: slides.length });
  };

  const openEdit = (slide: HeroSlide) => {
    setIsNew(false);
    setEditing({ ...slide });
  };

  const closeModal = () => setEditing(null);

  const handleFilePick = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    e.target.value = '';
    if (!file || !editing) return;

    const blobUrl = URL.createObjectURL(file);
    setEditing(prev => prev ? { ...prev, image: blobUrl } : prev);
    setUploadPct(0);

    try {
      const form = new FormData();
      form.append('file', file);

      const url = await new Promise<string>((resolve, reject) => {
        const xhr = new XMLHttpRequest();
        xhr.open('POST', '/api/admin/upload');
        xhr.upload.onprogress = ev => {
          if (ev.lengthComputable) setUploadPct(Math.round((ev.loaded / ev.total) * 100));
        };
        xhr.onload = () => {
          try {
            const data = JSON.parse(xhr.responseText);
            if (xhr.status >= 200 && xhr.status < 300 && data.url) {
              resolve(data.url);
            } else {
              reject(new Error(data.error ?? `HTTP ${xhr.status}`));
            }
          } catch {
            reject(new Error(`HTTP ${xhr.status}`));
          }
        };
        xhr.onerror = () => reject(new Error('Network error'));
        xhr.send(form);
      });

      URL.revokeObjectURL(blobUrl);
      setEditing(prev => prev ? { ...prev, image: url } : prev);
      showToast('อัปโหลดรูปสำเร็จ ✓');
    } catch (err) {
      setEditing(prev => prev ? { ...prev, image: prev.image === blobUrl ? '' : prev.image } : prev);
      URL.revokeObjectURL(blobUrl);
      showToast(`อัปโหลดไม่สำเร็จ: ${err instanceof Error ? err.message : 'unknown'}`, false);
    } finally {
      setUploadPct(null);
    }
  };

  const saveSlide = async () => {
    if (!editing) return;
    if (!editing.image || editing.image.startsWith('blob:')) {
      showToast('รอการอัปโหลดรูปภาพให้เสร็จก่อน', false);
      return;
    }
    setSaving(true);
    try {
      const { id, ...rest } = editing;
      const payload = isNew ? rest : editing;
      const res = await fetch('/api/admin/hero-slides', {
        method: isNew ? 'POST' : 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(payload),
      });
      const text = await res.text();
      if (!res.ok) {
        let msg = `HTTP ${res.status}`;
        try { msg = JSON.parse(text).error ?? msg; } catch { /* noop */ }
        throw new Error(msg);
      }
      const saved: HeroSlide = JSON.parse(text);
      setSlides(prev =>
        isNew
          ? [...prev, saved].sort((a, b) => a.sort_order - b.sort_order)
          : prev.map(s => s.id === saved.id ? saved : s)
      );
      closeModal();
      showToast('บันทึกสำเร็จ ✓');
    } catch (err) {
      showToast(`บันทึกไม่สำเร็จ: ${err instanceof Error ? err.message : 'unknown'}`, false);
    } finally {
      setSaving(false);
    }
  };

  const saveBanner = async () => {
    setSavingBanner(true);
    try {
      const res = await fetch('/api/admin/settings', {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ key: 'heroBanner', value: bannerConfig }),
      });
      if (!res.ok) throw new Error();
      showToast('บันทึกการตั้งค่าแบนเนอร์สำเร็จ ✓');
    } catch {
      showToast('บันทึกไม่สำเร็จ', false);
    } finally {
      setSavingBanner(false);
    }
  };

  const toggleEnabled = async (slide: HeroSlide) => {
    const next = !slide.enabled;
    setSlides(prev => prev.map(s => s.id === slide.id ? { ...s, enabled: next } : s));
    try {
      const res = await fetch('/api/admin/hero-slides', {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ id: slide.id, enabled: next }),
      });
      if (!res.ok) throw new Error();
      showToast(next ? 'เปิด slide แล้ว' : 'ปิด slide แล้ว');
    } catch {
      setSlides(prev => prev.map(s => s.id === slide.id ? { ...s, enabled: !next } : s));
      showToast('เกิดข้อผิดพลาด', false);
    }
  };

  const deleteSlide = async (slide: HeroSlide) => {
    if (!confirm(`ลบ slide "${slide.title || '(ไม่มีชื่อ)'}" ?`)) return;
    setSlides(prev => prev.filter(s => s.id !== slide.id));
    try {
      const res = await fetch(`/api/admin/hero-slides?id=${slide.id}`, { method: 'DELETE' });
      if (!res.ok) throw new Error();
      showToast('ลบสำเร็จ');
    } catch {
      load();
      showToast('ลบไม่สำเร็จ', false);
    }
  };

  const moveSlide = async (id: string, dir: -1 | 1) => {
    const idx = slides.findIndex(s => s.id === id);
    if (idx === -1) return;
    const swapIdx = idx + dir;
    if (swapIdx < 0 || swapIdx >= slides.length) return;
    const next = [...slides];
    const tmp = next[idx];
    next[idx]     = { ...next[swapIdx], sort_order: idx };
    next[swapIdx] = { ...tmp,           sort_order: swapIdx };
    setSlides(next);
    try {
      await Promise.all([
        fetch('/api/admin/hero-slides', {
          method: 'PUT', headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ id: next[idx].id,     sort_order: idx }),
        }),
        fetch('/api/admin/hero-slides', {
          method: 'PUT', headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ id: next[swapIdx].id, sort_order: swapIdx }),
        }),
      ]);
    } catch {
      load();
      showToast('เรียงลำดับไม่สำเร็จ', false);
    }
  };

  const displaySlides = themeFilter === 'all'
    ? slides
    : slides.filter(s => s.theme === themeFilter || s.theme === 'both');

  const isUploading = uploadPct !== null;

  return (
    <div className="max-w-5xl mx-auto px-6 py-8">

      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-center justify-between mb-8 pb-4 border-b border-[var(--color-border)] gap-4">
        <div className="flex flex-col gap-1">
          <Link href="/admin/dashboard"
            className="text-sm text-[var(--color-text-secondary)] hover:text-[var(--color-text-primary)] transition-colors flex items-center gap-2 w-fit">
            ← Back to Dashboard
          </Link>
          <h1 className="font-display text-2xl font-normal text-[var(--color-text-primary)]">🖼️ Hero Banner & Slides</h1>
          <p className="text-sm text-[var(--color-text-muted)]">จัดการรูปแบบแบนเนอร์และภาพสไลด์แบนเนอร์หน้าหลัก</p>
        </div>
        {activeTab === 'slides' && (
          <button onClick={() => openNew()}
            className="px-4 py-2 rounded-lg bg-[var(--color-accent)] text-white text-sm font-medium hover:opacity-90 transition-opacity shrink-0">
            + เพิ่ม Slide ใหม่
          </button>
        )}
      </div>

      {/* Toast */}
      {toast && (
        <div className={`mb-5 px-4 py-3 rounded-xl text-sm border flex items-start gap-2 ${
          toast.ok ? 'bg-green-500/10 border-green-500/30 text-green-600' : 'bg-red-500/10 border-red-500/30 text-red-500'
        }`}>
          <span className="shrink-0">{toast.ok ? '✅' : '❌'}</span>
          <span className="break-all">{toast.msg}</span>
        </div>
      )}

      {/* Tabs */}
      <div className="flex gap-4 border-b border-[var(--color-border)] mb-6">
        <button
          onClick={() => setActiveTab('banner')}
          className={`pb-3 text-sm font-medium transition-colors border-b-2 ${
            activeTab === 'banner'
              ? 'border-[var(--color-accent)] text-[var(--color-text-primary)]'
              : 'border-transparent text-[var(--color-text-muted)] hover:text-[var(--color-text-primary)]'
          }`}
        >
          ⚙️ รูปแบบแบนเนอร์
        </button>
        <button
          onClick={() => setActiveTab('slides')}
          className={`pb-3 text-sm font-medium transition-colors border-b-2 ${
            activeTab === 'slides'
              ? 'border-[var(--color-accent)] text-[var(--color-text-primary)]'
              : 'border-transparent text-[var(--color-text-muted)] hover:text-[var(--color-text-primary)]'
          }`}
        >
          🖼️ จัดการรูปสไลด์
        </button>
      </div>

      {/* BANNER SETTINGS TAB */}
      {activeTab === 'banner' && (
        <div className="bg-[var(--color-surface)] border border-[var(--color-border)] rounded-2xl p-6 space-y-6">
          <div className="space-y-2">
            <label className="block text-sm font-medium text-[var(--color-text-primary)]">รูปแบบแบนเนอร์</label>
            <select
              value={bannerConfig.type}
              onChange={(e) => setBannerConfig(s => ({ ...s, type: e.target.value as HeroBannerConfig['type'] }))}
              className="w-full px-4 py-2.5 rounded-xl border border-[var(--color-border)] bg-[var(--color-panel)] text-[var(--color-text-primary)] focus:outline-none focus:border-[var(--color-accent)]"
            >
              <option value="cinematic">✨ Cinematic (Interactive 3D Effect)</option>
              <option value="slide">🖼️ Slideshow (เลื่อนสลับภาพอัตโนมัติ)</option>
              <option value="video">🎥 Video Background</option>
              <option value="image">📸 Static Image</option>
            </select>
          </div>

          {bannerConfig.type === 'video' && (
            <div className="space-y-2">
              <label className="block text-sm font-medium text-[var(--color-text-primary)]">URL ของวิดีโอ (MP4)</label>
              <input
                value={bannerConfig.videoUrl || ''}
                onChange={(e) => setBannerConfig(s => ({ ...s, videoUrl: e.target.value }))}
                className="w-full px-4 py-2.5 rounded-xl border border-[var(--color-border)] bg-[var(--color-panel)] text-[var(--color-text-primary)] focus:outline-none focus:border-[var(--color-accent)]"
                placeholder="https://example.com/video.mp4"
              />
            </div>
          )}

          {bannerConfig.type === 'image' && (
            <>
              <div className="space-y-2">
                <label className="block text-sm font-medium text-[var(--color-text-primary)]">URL ของรูปภาพ</label>
                <input
                  value={bannerConfig.imageUrl || ''}
                  onChange={(e) => setBannerConfig(s => ({ ...s, imageUrl: e.target.value }))}
                  className="w-full px-4 py-2.5 rounded-xl border border-[var(--color-border)] bg-[var(--color-panel)] text-[var(--color-text-primary)] focus:outline-none focus:border-[var(--color-accent)]"
                  placeholder="/images/banners/banner.png"
                />
              </div>
              <div className="space-y-2">
                <label className="block text-sm font-medium text-[var(--color-text-primary)]">ลิงก์เมื่อคลิกรูปภาพ (ปล่อยว่างได้)</label>
                <input
                  value={bannerConfig.clickUrl || ''}
                  onChange={(e) => setBannerConfig(s => ({ ...s, clickUrl: e.target.value }))}
                  className="w-full px-4 py-2.5 rounded-xl border border-[var(--color-border)] bg-[var(--color-panel)] text-[var(--color-text-primary)] focus:outline-none focus:border-[var(--color-accent)]"
                  placeholder="https://youtube.com/..."
                />
              </div>
            </>
          )}

          <div className="flex items-center justify-between p-4 rounded-xl border border-[var(--color-border)] bg-[var(--color-panel)]">
            <div>
              <p className="text-sm font-medium text-[var(--color-text-primary)]">แสดงคำแนะนำการเลื่อนจอ (Scroll to Explore)</p>
              <p className="text-xs text-[var(--color-text-muted)] mt-0.5">ไอคอนลูกศรเลื่อนลงบริเวณด้านล่างของจอ</p>
            </div>
            <button
              onClick={() => setBannerConfig(s => ({ ...s, showScrollHint: !(s.showScrollHint ?? true) }))}
              className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors ${
                (bannerConfig.showScrollHint ?? true) ? 'bg-green-500' : 'bg-[#444]'
              }`}
            >
              <span className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${
                (bannerConfig.showScrollHint ?? true) ? 'translate-x-6' : 'translate-x-1'
              }`} />
            </button>
          </div>

          <div className="flex justify-end pt-4 border-t border-[var(--color-border)]">
             <button onClick={saveBanner} disabled={savingBanner} className="px-6 py-2.5 rounded-lg bg-[var(--color-accent)] text-white text-sm font-semibold hover:opacity-90 disabled:opacity-50 min-w-[130px]">
               {savingBanner ? '⏳ กำลังบันทึก...' : '💾 บันทึกการตั้งค่า'}
             </button>
          </div>
        </div>
      )}

      {/* SLIDES TAB */}
      {activeTab === 'slides' && (
        <>
          {/* Theme tabs */}
          <div className="mb-5 flex items-center gap-2 flex-wrap">
            {(['all', 'light', 'dark'] as const).map(key => {
              const label = key === 'all' ? '🗂️ ทั้งหมด' : key === 'light' ? '☀️ Light' : '🌙 Dark';
              const count = key === 'all' ? slides.length : slides.filter(s => s.theme === key || s.theme === 'both').length;
              return (
                <button key={key} onClick={() => setThemeFilter(key)}
                  className={`px-4 py-1.5 rounded-full text-sm border transition-all ${
                    themeFilter === key
                      ? 'bg-[var(--color-accent)] text-white border-transparent'
                      : 'bg-[var(--color-panel)] border-[var(--color-border)] text-[var(--color-text-secondary)] hover:border-[var(--color-accent)]'
                  }`}>
                  {label} <span className="opacity-60 text-xs">({count})</span>
                </button>
              );
            })}
            <button onClick={load}
              className="ml-auto text-xs px-3 py-1.5 rounded-full border border-[var(--color-border)] text-[var(--color-text-muted)] hover:border-[var(--color-accent)] transition-all">
              🔄 รีเฟรช
            </button>
          </div>

      {/* Slide list */}
      {loading ? (
        <div className="space-y-3">
          {[1, 2, 3].map(i => <div key={i} className="h-24 rounded-xl bg-[var(--color-surface)] animate-pulse" />)}
        </div>
      ) : displaySlides.length === 0 ? (
        <div className="text-center py-16 text-[var(--color-text-muted)]">
          <div className="text-4xl mb-3">🖼️</div>
          <p>ยังไม่มี slide{themeFilter !== 'all' ? ` สำหรับ ${themeFilter} theme` : ''}</p>
          <button onClick={() => openNew()}
            className="mt-4 px-4 py-2 rounded-lg bg-[var(--color-accent)] text-white text-sm hover:opacity-90 transition-opacity">
            + เพิ่ม Slide แรก
          </button>
        </div>
      ) : (
        <div className="space-y-3">
          {displaySlides.map((slide, idx) => {
            const badge = themeBadge(slide.theme);
            return (
              <div key={slide.id}
                className={`flex items-center gap-4 p-4 rounded-xl border transition-all ${
                  slide.enabled
                    ? 'bg-[var(--color-surface)] border-[var(--color-border)]'
                    : 'bg-[var(--color-panel)] border-[var(--color-border)] opacity-75'
                }`}>
                {/* Thumbnail */}
                <div className="relative w-20 h-12 rounded-lg overflow-hidden shrink-0 bg-[var(--color-panel)]">
                  {slide.image && (
                    <Image src={slide.image} alt={slide.title ?? ''} fill className="object-cover" sizes="80px" unoptimized />
                  )}
                </div>
                {/* Info */}
                <div className="flex-1 min-w-0">
                  <p className="text-sm font-medium text-[var(--color-text-primary)] truncate">
                    {slide.title || '(ไม่มีชื่อ)'}
                    {slide.title_thai && <span className="ml-2 text-xs text-[var(--color-text-muted)] font-thai">{slide.title_thai}</span>}
                  </p>
                  {slide.subtitle && <p className="text-xs text-[var(--color-text-muted)] truncate">{slide.subtitle}</p>}
                  {slide.link && <p className="text-xs text-[#6cbfd0] truncate mt-0.5">🔗 {slide.link}</p>}
                </div>
                {/* Status badge */}
                <span className={`text-xs px-2 py-0.5 rounded-full shrink-0 ${
                  slide.enabled ? 'bg-green-500/15 text-green-600' : 'bg-[#87867f]/15 text-[#87867f]'
                }`}>{slide.enabled ? 'เปิด' : 'ปิด'}</span>
                {/* Theme badge */}
                <span className={`hidden sm:inline text-xs px-2 py-0.5 rounded-full shrink-0 border ${badge.cls}`}>{badge.label}</span>
                {/* ViewState badge */}
                {slide.view_state && slide.view_state !== 'both' && (
                  <span className={`hidden sm:inline text-xs px-2 py-0.5 rounded-full shrink-0 border ${viewStateBadge(slide.view_state).cls}`}>{viewStateBadge(slide.view_state).label}</span>
                )}
                {/* Actions */}
                <div className="flex items-center gap-1 shrink-0">
                  <button onClick={() => moveSlide(slide.id, -1)} disabled={idx === 0}
                    className="w-8 h-8 rounded-lg flex items-center justify-center bg-[var(--color-panel)] border border-[var(--color-border)] text-[var(--color-text-primary)] hover:border-[var(--color-accent)] disabled:opacity-25 disabled:cursor-not-allowed transition-all text-xs font-bold" title="ขึ้น">↑</button>
                  <button onClick={() => moveSlide(slide.id, 1)} disabled={idx === displaySlides.length - 1}
                    className="w-8 h-8 rounded-lg flex items-center justify-center bg-[var(--color-panel)] border border-[var(--color-border)] text-[var(--color-text-primary)] hover:border-[var(--color-accent)] disabled:opacity-25 disabled:cursor-not-allowed transition-all text-xs font-bold" title="ลง">↓</button>
                  <button onClick={() => toggleEnabled(slide)}
                    className={`w-8 h-8 rounded-lg flex items-center justify-center border transition-all text-sm ${
                      slide.enabled
                        ? 'bg-green-500/15 border-green-500/40 text-green-600 hover:bg-green-500/25'
                        : 'bg-[var(--color-panel)] border-[var(--color-border)] text-[var(--color-text-secondary)] hover:border-green-500/40'
                    }`}
                    title={slide.enabled ? 'ปิด slide' : 'เปิด slide'}>{slide.enabled ? '👁' : '🙈'}</button>
                  <button onClick={() => openEdit(slide)}
                    className="w-8 h-8 rounded-lg flex items-center justify-center bg-[#6cbfd0]/15 border border-[#6cbfd0]/40 text-[#6cbfd0] hover:bg-[#6cbfd0]/25 transition-all" title="แก้ไข">✏️</button>
                  <button onClick={() => deleteSlide(slide)}
                    className="w-8 h-8 rounded-lg flex items-center justify-center bg-red-500/10 border border-red-500/30 text-red-400 hover:bg-red-500/20 transition-all" title="ลบ">🗑️</button>
                </div>
              </div>
            );
          })}
        </div>
      )}
        </>
      )}

      {/* Modal */}
      {editing && (
        <div className="fixed inset-0 z-50 flex items-end sm:items-center justify-center p-0 sm:p-6 bg-black/60 backdrop-blur-sm">
          <div className="w-full max-w-xl bg-[var(--color-surface)] border border-[var(--color-border)] rounded-t-2xl sm:rounded-2xl shadow-2xl flex flex-col max-h-[85dvh] sm:max-h-[88dvh]">

            {/* Modal header */}
            <div className="flex items-center justify-between px-6 py-4 border-b border-[var(--color-border)] shrink-0">
              <h2 className="font-display text-lg font-normal">{isNew ? '+ เพิ่ม Slide ใหม่' : '✏️ แก้ไข Slide'}</h2>
              <button onClick={closeModal}
                className="w-8 h-8 rounded-full flex items-center justify-center hover:bg-[var(--color-panel)] text-[var(--color-text-muted)] transition-colors">✕</button>
            </div>

            {/* Modal body */}
            <div className="px-6 py-5 space-y-5 overflow-y-auto flex-1 min-h-0">

              {/* Image */}
              <div>
                <label className="block text-xs text-[var(--color-text-muted)] uppercase tracking-wider mb-2">รูปภาพ *</label>

                {editing.image ? (
                  <div className="relative w-full h-44 rounded-xl overflow-hidden mb-3 bg-[var(--color-panel)]">
                    {/* eslint-disable-next-line @next/next/no-img-element */}
                    <img src={editing.image} alt="preview" className="w-full h-full object-cover" />
                    {isUploading && (
                      <div className="absolute inset-0 bg-black/60 flex flex-col items-center justify-center gap-2">
                        <div className="w-48 h-1.5 rounded-full bg-white/20 overflow-hidden">
                          <div className="h-full bg-white rounded-full transition-all duration-150" style={{ width: `${uploadPct}%` }} />
                        </div>
                        <span className="text-white text-xs font-medium">⏳ กำลังอัปโหลด {uploadPct}%</span>
                      </div>
                    )}
                  </div>
                ) : (
                  <div
                    onClick={() => !isUploading && fileRef.current?.click()}
                    className="w-full h-44 rounded-xl mb-3 bg-[var(--color-panel)] border-2 border-dashed border-[var(--color-border)] flex flex-col items-center justify-center gap-2 cursor-pointer hover:border-[var(--color-accent)] transition-colors">
                    <span className="text-3xl">🖼️</span>
                    <span className="text-sm text-[var(--color-text-muted)]">คลิกเพื่อเลือกรูปภาพ</span>
                    <span className="text-xs text-[var(--color-text-muted)]">jpg · png · webp · gif · สูงสุด 5MB</span>
                  </div>
                )}

                <div className="flex gap-2">
                  <input
                    type="text"
                    placeholder="/images/banners/banner.png หรือ https://..."
                    value={editing.image.startsWith('blob:') ? '' : editing.image}
                    readOnly={isUploading}
                    onChange={e => setEditing(prev => prev ? { ...prev, image: e.target.value } : prev)}
                    className="flex-1 px-3 py-2 text-sm rounded-lg bg-[var(--color-panel)] border border-[var(--color-border)] text-[var(--color-text-primary)] focus:outline-none focus:border-[var(--color-accent)]"
                  />
                  <button
                    onClick={() => fileRef.current?.click()}
                    disabled={isUploading || saving}
                    className="px-3 py-2 text-sm rounded-lg bg-[var(--color-panel)] border border-[var(--color-border)] hover:border-[var(--color-accent)] transition-colors disabled:opacity-50 whitespace-nowrap">
                    {isUploading ? `${uploadPct}%` : '📁 เลือกไฟล์'}
                  </button>
                  <input ref={fileRef} type="file" accept="image/jpeg,image/png,image/webp,image/gif" className="hidden" onChange={handleFilePick} />
                </div>
              </div>

              {/* Titles */}
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="block text-xs text-[var(--color-text-muted)] uppercase tracking-wider mb-1">Title (EN)</label>
                  <input type="text" value={editing.title ?? ''}
                    onChange={e => setEditing(p => p ? { ...p, title: e.target.value } : p)}
                    className="w-full px-3 py-2 text-sm rounded-lg bg-[var(--color-panel)] border border-[var(--color-border)] text-[var(--color-text-primary)] focus:outline-none focus:border-[var(--color-accent)]" />
                </div>
                <div>
                  <label className="block text-xs text-[var(--color-text-muted)] uppercase tracking-wider mb-1 font-thai">ชื่อ (TH)</label>
                  <input type="text" value={editing.title_thai ?? ''}
                    onChange={e => setEditing(p => p ? { ...p, title_thai: e.target.value } : p)}
                    className="w-full px-3 py-2 text-sm rounded-lg bg-[var(--color-panel)] border border-[var(--color-border)] text-[var(--color-text-primary)] focus:outline-none focus:border-[var(--color-accent)] font-thai" />
                </div>
              </div>

              {/* Subtitles */}
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="block text-xs text-[var(--color-text-muted)] uppercase tracking-wider mb-1">Subtitle (EN)</label>
                  <input type="text" value={editing.subtitle ?? ''}
                    onChange={e => setEditing(p => p ? { ...p, subtitle: e.target.value } : p)}
                    className="w-full px-3 py-2 text-sm rounded-lg bg-[var(--color-panel)] border border-[var(--color-border)] text-[var(--color-text-primary)] focus:outline-none focus:border-[var(--color-accent)]" />
                </div>
                <div>
                  <label className="block text-xs text-[var(--color-text-muted)] uppercase tracking-wider mb-1 font-thai">Subtitle (TH)</label>
                  <input type="text" value={editing.subtitle_thai ?? ''}
                    onChange={e => setEditing(p => p ? { ...p, subtitle_thai: e.target.value } : p)}
                    className="w-full px-3 py-2 text-sm rounded-lg bg-[var(--color-panel)] border border-[var(--color-border)] text-[var(--color-text-primary)] focus:outline-none focus:border-[var(--color-accent)] font-thai" />
                </div>
              </div>

              {/* Link */}
              <div>
                <label className="block text-xs text-[var(--color-text-muted)] uppercase tracking-wider mb-1">Link เมื่อคลิก</label>
                <input type="text" placeholder="/artist/namtan หรือ https://..."
                  value={editing.link ?? ''}
                  onChange={e => setEditing(p => p ? { ...p, link: e.target.value } : p)}
                  className="w-full px-3 py-2 text-sm rounded-lg bg-[var(--color-panel)] border border-[var(--color-border)] text-[var(--color-text-primary)] focus:outline-none focus:border-[var(--color-accent)]" />
              </div>

              {/* Theme */}
              <div>
                <label className="block text-xs text-[var(--color-text-muted)] uppercase tracking-wider mb-2">แสดงบน Theme</label>
                <div className="flex gap-2">
                  {THEME_OPTIONS.map(opt => (
                    <button key={opt.value}
                      onClick={() => setEditing(p => p ? { ...p, theme: opt.value } : p)}
                      className={`flex-1 py-2 rounded-lg text-xs border transition-all ${
                        editing.theme === opt.value ? opt.cls : 'bg-[var(--color-panel)] border-[var(--color-border)] text-[var(--color-text-muted)] hover:border-[var(--color-accent)]'
                      }`}>
                      {opt.label}
                    </button>
                  ))}
                </div>
              </div>

              {/* View State */}
              <div>
                <label className="block text-xs text-[var(--color-text-muted)] uppercase tracking-wider mb-2">แสดงสำหรับ</label>
                <div className="grid grid-cols-4 gap-2">
                  {VIEW_STATE_OPTIONS.map(opt => (
                    <button key={opt.value}
                      onClick={() => setEditing(p => p ? { ...p, view_state: opt.value } : p)}
                      className={`py-2 rounded-lg text-xs border transition-all ${
                        editing.view_state === opt.value ? opt.cls : 'bg-[var(--color-panel)] border-[var(--color-border)] text-[var(--color-text-muted)] hover:border-[var(--color-accent)]'
                      }`}>
                      {opt.label}
                    </button>
                  ))}
                </div>
              </div>

              {/* Order + Status */}
              <div className="grid grid-cols-2 gap-3">
                <div>
                  <label className="block text-xs text-[var(--color-text-muted)] uppercase tracking-wider mb-1">ลำดับ</label>
                  <input type="number" min={0} value={editing.sort_order}
                    onChange={e => setEditing(p => p ? { ...p, sort_order: parseInt(e.target.value) || 0 } : p)}
                    className="w-full px-3 py-2 text-sm rounded-lg bg-[var(--color-panel)] border border-[var(--color-border)] text-[var(--color-text-primary)] focus:outline-none focus:border-[var(--color-accent)]" />
                </div>
                <div>
                  <label className="block text-xs text-[var(--color-text-muted)] uppercase tracking-wider mb-1">สถานะ</label>
                  <button
                    onClick={() => setEditing(p => p ? { ...p, enabled: !p.enabled } : p)}
                    className={`w-full px-3 py-2 text-sm rounded-lg border transition-all ${
                      editing.enabled
                        ? 'bg-green-500/15 border-green-500/40 text-green-600'
                        : 'bg-[var(--color-panel)] border-[var(--color-border)] text-[var(--color-text-muted)]'
                    }`}>
                    {editing.enabled ? '✅ เปิดแสดง' : '◻️ ปิดซ่อน'}
                  </button>
                </div>
              </div>

            </div>

            {/* Modal footer */}
            <div className="flex items-center justify-end gap-3 px-6 py-4 border-t border-[var(--color-border)] shrink-0 bg-[var(--color-surface)]">
              <button onClick={closeModal}
                className="px-5 py-2.5 rounded-lg text-sm border border-[var(--color-border)] bg-[var(--color-panel)] text-[var(--color-text-primary)] hover:border-[var(--color-accent)] transition-colors">
                ยกเลิก
              </button>
              <button
                onClick={saveSlide}
                disabled={saving || isUploading}
                className="px-6 py-2.5 rounded-lg bg-[var(--color-accent)] text-white text-sm font-semibold hover:opacity-90 disabled:opacity-50 disabled:cursor-not-allowed transition-all min-w-[130px] shadow-sm">
                {saving ? '⏳ กำลังบันทึก...' : isUploading ? `⏳ อัปโหลด ${uploadPct}%` : '💾 บันทึก'}
              </button>
            </div>

          </div>
        </div>
      )}

    </div>
  );
}

'use client';

import { useState, useEffect, useMemo } from 'react';
import {
  WIDGET_OPTIONS, SLOT_DEFS, type WidgetType,
  STATS_TILE_OPTIONS, STATS_STRIP_DEFS, DEFAULT_STATS_STRIP, type StatsTileType,
  type BentoSlotLink, isDualWidget,
} from '@/components/dashboard/EditorialCheatSheet';

// ── Widget visual metadata (for miniature preview) ────────────────────────────
const WIDGET_META: Record<WidgetType, { icon: string; short: string; accent?: string }> = {
  ig_followers:     { icon: '📸', short: 'IG',        accent: '#E1306C' },
  x_followers:      { icon: '𝕏',  short: 'X',         accent: '#888' },
  tiktok_followers: { icon: '🎵', short: 'TikTok',    accent: '#00f2ea' },
  weibo_followers:  { icon: '🌐', short: 'Weibo',     accent: '#e6162d' },
  namtan_emv:       { icon: '💙', short: 'NT EMV',    accent: '#6cbfd0' },
  film_emv:         { icon: '💛', short: 'FL EMV',    accent: '#fbdf74' },
  emv_split:        { icon: '🍩', short: 'EMV Split' },
  fan_audience:     { icon: '🌍', short: 'Audience' },
  namtan_portrait:  { icon: '🖼️', short: 'น้ำตาล',    accent: '#6cbfd0' },
  film_portrait:    { icon: '🖼️', short: 'ฟิล์ม',     accent: '#fbdf74' },
  featured_series:  { icon: '🎥', short: 'ซีรีส์' },
  featured_music:   { icon: '🎶', short: 'เพลง' },
  series_count:     { icon: '📊', short: 'Series' },
  brands_count:     { icon: '🏷️', short: 'Brands' },
  awards_count:     { icon: '🏆', short: 'Awards' },
  nt_brands_list:   { icon: '🏷️', short: 'NT Brands', accent: '#6cbfd0' },
  fl_brands_list:   { icon: '🏷️', short: 'FL Brands', accent: '#fbdf74' },
  nt_works_pie:     { icon: '🥧', short: 'NT งาน',    accent: '#6cbfd0' },
  fl_works_pie:     { icon: '🥧', short: 'FL งาน',    accent: '#fbdf74' },
  hidden:           { icon: '✕',  short: 'ซ่อน',      accent: '#555' },
};

// Stats tile visual metadata (for miniature preview)
const STATS_TILE_META: Record<StatsTileType, { icon: string; short: string; accent?: string }> = {
  nt_awards:  { icon: '🏆', short: 'NT Awards',  accent: '#6cbfd0' },
  fl_awards:  { icon: '🏆', short: 'FL Awards',  accent: '#fbdf74' },
  nt_brands:  { icon: '🏷️', short: 'NT Brands',  accent: '#6cbfd0' },
  fl_brands:  { icon: '🏷️', short: 'FL Brands',  accent: '#fbdf74' },
  nt_ig:      { icon: '📸', short: 'NT IG',      accent: '#6cbfd0' },
  fl_ig:      { icon: '📸', short: 'FL IG',      accent: '#fbdf74' },
  nt_x:       { icon: '𝕏',  short: 'NT X',       accent: '#6cbfd0' },
  fl_x:       { icon: '𝕏',  short: 'FL X',       accent: '#fbdf74' },
  nt_tiktok:  { icon: '🎵', short: 'NT TikTok',  accent: '#6cbfd0' },
  fl_tiktok:  { icon: '🎵', short: 'FL TikTok',  accent: '#fbdf74' },
  nt_weibo:   { icon: '🌐', short: 'NT Weibo',   accent: '#6cbfd0' },
  fl_weibo:   { icon: '🌐', short: 'FL Weibo',   accent: '#fbdf74' },
  nt_series:  { icon: '📺', short: 'NT Series',  accent: '#6cbfd0' },
  fl_series:  { icon: '📺', short: 'FL Series',  accent: '#fbdf74' },
  nt_emv:     { icon: '💙', short: 'NT EMV',     accent: '#6cbfd0' },
  fl_emv:     { icon: '💛', short: 'FL EMV',     accent: '#fbdf74' },
  hidden:     { icon: '✕',  short: 'ซ่อน',       accent: '#555' },
};

// Grid position map for the miniature 4×3 preview
const SLOT_GRID: Record<string, string> = {
  A: 'col-start-1 row-start-1',
  B: 'col-start-2 row-start-1',
  C: 'col-start-4 row-start-1 row-span-2',
  D: 'col-start-3 row-start-1 row-span-2',
  E: 'col-start-1 row-start-2',
  F: 'col-start-2 row-start-2',
  H: 'col-start-1 row-start-3',
  I: 'col-start-2 row-start-3',
  J: 'col-start-3 row-start-3',
  K: 'col-start-4 row-start-3',
};

interface LiveDashboardConfig {
  showArtists:         string[];
  showPlatforms:       string[];
  showFollowerSection: boolean;
  showQuickLinks:      boolean;
  bento:               Record<string, WidgetType>;
  statsStrip:          Record<string, StatsTileType>;
  bentoLinks?:         Record<string, BentoSlotLink>;
}

const DEFAULT_BENTO: Record<string, WidgetType> = Object.fromEntries(
  SLOT_DEFS.map(s => [s.id, s.defaultWidget])
) as Record<string, WidgetType>;

const DEFAULT_CONFIG: LiveDashboardConfig = {
  showArtists: ['namtan', 'film', 'luna'],
  showPlatforms: ['ig', 'x', 'tiktok', 'weibo'],
  showFollowerSection: true,
  showQuickLinks:      true,
  bento:               DEFAULT_BENTO,
  statsStrip:          DEFAULT_STATS_STRIP,
  bentoLinks:          {},
};

const ARTISTS = [
  { value: 'namtan', label: '💙 น้ำตาล (Namtan)' },
  { value: 'film',   label: '💛 ฟิล์ม (Film)'   },
  { value: 'luna',   label: '💜 ลูน่า (Luna)'   },
];

const PLATFORMS = [
  { value: 'ig',     label: '📸 Instagram (IG)' },
  { value: 'x',      label: '𝕏 X (Twitter)'    },
  { value: 'tiktok', label: '🎵 TikTok'         },
  { value: 'weibo',  label: '🌐 Weibo'          },
];

function toggleItem<T extends string>(list: T[], item: T): T[] {
  return list.includes(item) ? list.filter(i => i !== item) : [...list, item];
}

export default function LiveDashboardSettingsPage() {
  const [config, setConfig] = useState<LiveDashboardConfig>(DEFAULT_CONFIG);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [saved, setSaved] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [showPreview, setShowPreview] = useState(true);
  const [highlightSlot, setHighlightSlot] = useState<string | null>(null);
  const [highlightTile, setHighlightTile] = useState<string | null>(null);

  const changedCount = useMemo(
    () => SLOT_DEFS.filter(s => (config.bento[s.id] ?? s.defaultWidget) !== s.defaultWidget).length,
    [config.bento]
  );
  const statsChangedCount = useMemo(
    () => STATS_STRIP_DEFS.filter(s => (config.statsStrip[s.id] ?? s.defaultTile) !== s.defaultTile).length,
    [config.statsStrip]
  );

  useEffect(() => {
    fetch('/api/admin/settings')
      .then(r => r.ok ? r.json() : null)
      .then(data => {
        if (data?.liveDashboardConfig) {
          setConfig({
            ...DEFAULT_CONFIG,
            ...data.liveDashboardConfig,
            bento: { ...DEFAULT_BENTO, ...(data.liveDashboardConfig.bento ?? {}) },
            statsStrip: { ...DEFAULT_STATS_STRIP, ...(data.liveDashboardConfig.statsStrip ?? {}) },
            bentoLinks: { ...(data.liveDashboardConfig.bentoLinks ?? {}) },
          });
        }
      })
      .catch(() => {})
      .finally(() => setLoading(false));
  }, []);

  async function handleSave() {
    setSaving(true);
    setError(null);
    try {
      const res = await fetch('/api/admin/settings', {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ key: 'liveDashboardConfig', value: config }),
      });
      if (!res.ok) throw new Error('บันทึกไม่สำเร็จ');
      setSaved(true);
      setTimeout(() => setSaved(false), 2500);
    } catch (e: unknown) {
      setError(e instanceof Error ? e.message : 'เกิดข้อผิดพลาด');
    } finally {
      setSaving(false);
    }
  }

  function setBento(slotId: string, widget: WidgetType) {
    setConfig(c => ({ ...c, bento: { ...c.bento, [slotId]: widget } }));
  }

  function setBentoLink(slotId: string, field: keyof BentoSlotLink, value: string) {
    setConfig(c => {
      const prev = c.bentoLinks?.[slotId] ?? {};
      const updated = { ...prev, [field]: value || undefined };
      // Clean empty entries
      if (!updated.namtan && !updated.film && !updated.single) {
        const { [slotId]: _, ...rest } = c.bentoLinks ?? {};
        return { ...c, bentoLinks: rest };
      }
      return { ...c, bentoLinks: { ...(c.bentoLinks ?? {}), [slotId]: updated } };
    });
  }

  function setStatsTile(tileId: string, tile: StatsTileType) {
    setConfig(c => ({ ...c, statsStrip: { ...c.statsStrip, [tileId]: tile } }));
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-[60vh]">
        <div className="animate-pulse text-[var(--color-text-secondary)]">กำลังโหลด...</div>
      </div>
    );
  }

  return (
    <div className="max-w-3xl mx-auto px-6 py-8">
      {/* Header */}
      <div className="mb-8 pb-4 border-b border-[var(--color-border)]">
        <h1 className="font-display text-2xl font-normal text-[var(--color-text-primary)]">
          <span className="bg-gradient-to-r from-[#6cbfd0] to-[#fbdf74] bg-clip-text text-transparent">
            Live Dashboard
          </span>
          <span className="text-[var(--color-text-secondary)] ml-3 text-lg">ตั้งค่าการแสดงผล</span>
        </h1>
        <p className="text-sm text-[var(--color-text-muted)] mt-1">
          กำหนดข้อมูลที่จะแสดงในส่วน Live Dashboard บนหน้าแรกของเว็บไซต์
        </p>
      </div>

      <div className="space-y-6">
        {/* Artists */}
        <div className="bg-[var(--color-surface)] rounded-xl p-6 border border-[var(--color-border)]">
          <h2 className="text-sm font-semibold text-[var(--color-text-primary)] mb-1">ศิลปินที่แสดง</h2>
          <p className="text-xs text-[var(--color-text-muted)] mb-4">เลือกศิลปินที่ต้องการแสดง Follower Card</p>
          <div className="space-y-3">
            {ARTISTS.map(({ value, label }) => (
              <label key={value} className="flex items-center gap-3 cursor-pointer">
                <input
                  type="checkbox"
                  checked={config.showArtists.includes(value)}
                  onChange={() => setConfig(c => ({ ...c, showArtists: toggleItem(c.showArtists, value) }))}
                  className="w-4 h-4 rounded accent-[#6cbfd0]"
                />
                <span className="text-sm text-[var(--color-text-primary)]">{label}</span>
              </label>
            ))}
          </div>
        </div>

        {/* Platforms */}
        <div className="bg-[var(--color-surface)] rounded-xl p-6 border border-[var(--color-border)]">
          <h2 className="text-sm font-semibold text-[var(--color-text-primary)] mb-1">แพลตฟอร์มที่แสดง</h2>
          <p className="text-xs text-[var(--color-text-muted)] mb-4">เลือกแพลตฟอร์มที่ต้องการแสดงยอด Followers</p>
          <div className="space-y-3">
            {PLATFORMS.map(({ value, label }) => (
              <label key={value} className="flex items-center gap-3 cursor-pointer">
                <input
                  type="checkbox"
                  checked={config.showPlatforms.includes(value)}
                  onChange={() => setConfig(c => ({ ...c, showPlatforms: toggleItem(c.showPlatforms, value) }))}
                  className="w-4 h-4 rounded accent-[#6cbfd0]"
                />
                <span className="text-sm text-[var(--color-text-primary)]">{label}</span>
              </label>
            ))}
          </div>
        </div>

        {/* Sections */}
        <div className="bg-[var(--color-surface)] rounded-xl p-6 border border-[var(--color-border)]">
          <h2 className="text-sm font-semibold text-[var(--color-text-primary)] mb-1">ส่วนที่แสดง</h2>
          <p className="text-xs text-[var(--color-text-muted)] mb-4">เปิด/ปิดการแสดงแต่ละ section</p>
          <div className="space-y-3">
            <label className="flex items-center gap-3 cursor-pointer">
              <input
                type="checkbox"
                checked={config.showFollowerSection}
                onChange={e => setConfig(c => ({ ...c, showFollowerSection: e.target.checked }))}
                className="w-4 h-4 rounded accent-[#6cbfd0]"
              />
              <div>
                <span className="text-sm text-[var(--color-text-primary)]">📊 Follower Cards</span>
                <p className="text-xs text-[var(--color-text-muted)]">แสดงยอด Followers แต่ละศิลปินแยกตามแพลตฟอร์ม</p>
              </div>
            </label>
            <label className="flex items-center gap-3 cursor-pointer">
              <input
                type="checkbox"
                checked={config.showQuickLinks}
                onChange={e => setConfig(c => ({ ...c, showQuickLinks: e.target.checked }))}
                className="w-4 h-4 rounded accent-[#6cbfd0]"
              />
              <div>
                <span className="text-sm text-[var(--color-text-primary)]">🔗 Quick Links</span>
                <p className="text-xs text-[var(--color-text-muted)]">ปุ่มลิงก์ด่วน — Media / Social / Stats / Community</p>
              </div>
            </label>
          </div>
        </div>

        {/* ── Bento Grid Visual Preview ──────────────────────────────────── */}
        <div className="bg-[var(--color-surface)] rounded-xl border border-[var(--color-border)] overflow-hidden">
          <button
            onClick={() => setShowPreview(p => !p)}
            className="w-full flex items-center justify-between p-6 text-left hover:bg-[var(--color-border)]/10 transition-colors"
          >
            <div>
              <h2 className="text-sm font-semibold text-[var(--color-text-primary)]">
                👁 Preview — Bento Grid Layout
              </h2>
              <p className="text-xs text-[var(--color-text-muted)] mt-0.5">
                ตัวอย่าง layout ที่จะแสดงบนหน้าแรก
                {changedCount > 0 && (
                  <span className="ml-2 text-[#6cbfd0]">({changedCount} ช่องที่เปลี่ยน)</span>
                )}
              </p>
            </div>
            <span className="text-[var(--color-text-muted)] text-sm">{showPreview ? '▲' : '▼'}</span>
          </button>

          {showPreview && (
            <div className="px-6 pb-6">
              {/* 4-col x 3-row miniature grid */}
              <div className="grid grid-cols-4 auto-rows-[72px] gap-1.5">
                {SLOT_DEFS.map(slot => {
                  const widget = (config.bento[slot.id] ?? slot.defaultWidget) as WidgetType;
                  const meta = WIDGET_META[widget];
                  const isHidden = widget === 'hidden';
                  const isHighlighted = highlightSlot === slot.id;
                  const isChanged = widget !== slot.defaultWidget;

                  return (
                    <div
                      key={slot.id}
                      className={`rounded-lg border relative flex flex-col items-center justify-center gap-0.5 transition-all duration-200 cursor-default
                        ${SLOT_GRID[slot.id]}
                        ${isHidden
                          ? 'border-dashed border-[var(--color-border)] bg-transparent opacity-40'
                          : isHighlighted
                            ? 'border-[#6cbfd0] bg-[#6cbfd0]/10 scale-[1.03] shadow-lg shadow-[#6cbfd0]/10'
                            : 'border-[var(--color-border)] bg-[var(--color-panel)]'
                        }`}
                      onMouseEnter={() => setHighlightSlot(slot.id)}
                      onMouseLeave={() => setHighlightSlot(null)}
                    >
                      {/* Slot badge */}
                      <span className={`absolute top-1 left-1.5 text-[8px] font-bold ${isChanged ? 'text-[#6cbfd0]' : 'text-[var(--color-text-muted)]'}`}>
                        {slot.id}
                      </span>
                      {/* Widget icon */}
                      <span className="text-lg leading-none">{meta.icon}</span>
                      {/* Widget short name */}
                      <span
                        className="text-[9px] font-medium leading-tight text-center"
                        style={{ color: meta.accent ?? 'var(--color-text-secondary)' }}
                      >
                        {meta.short}
                      </span>
                      {/* Changed dot */}
                      {isChanged && !isHidden && (
                        <span className="absolute top-1 right-1.5 w-1.5 h-1.5 rounded-full bg-[#6cbfd0]" />
                      )}
                    </div>
                  );
                })}
              </div>

              {/* Legend */}
              <div className="flex items-center gap-4 mt-3 text-[9px] text-[var(--color-text-muted)]">
                <span className="flex items-center gap-1">
                  <span className="w-1.5 h-1.5 rounded-full bg-[#6cbfd0]" /> เปลี่ยนจาก default
                </span>
                <span className="flex items-center gap-1">
                  <span className="w-4 h-3 rounded border border-dashed border-[var(--color-border)] inline-block opacity-40" /> ซ่อน
                </span>
              </div>
            </div>
          )}
        </div>

        {/* ── Bento Grid Layout ─────────────────────────────────────────── */}
        <div className="bg-[var(--color-surface)] rounded-xl p-6 border border-[var(--color-border)]">
          <h2 className="text-sm font-semibold text-[var(--color-text-primary)] mb-1">
            🔲 Data Cheat Sheet — กำหนด Widget แต่ละช่อง
          </h2>
          <p className="text-xs text-[var(--color-text-muted)] mb-5">
            เลือกว่าแต่ละช่องใน Bento Grid จะแสดงข้อมูลอะไร
            (ตำแหน่ง A–K คงที่, เปลี่ยนได้แค่เนื้อหา)
          </p>

          <div className="space-y-2">
            {SLOT_DEFS.map(slot => {
              const current = config.bento[slot.id] ?? slot.defaultWidget;
              const isHighlighted = highlightSlot === slot.id;
              const dual = isDualWidget(current);
              const link = config.bentoLinks?.[slot.id] ?? {};
              return (
                <div
                  key={slot.id}
                  className={`rounded-lg px-3 py-2.5 border transition-all duration-200
                    ${isHighlighted
                      ? 'bg-[#6cbfd0]/10 border-[#6cbfd0]/40'
                      : 'bg-[var(--color-panel)] border-[var(--color-border)]'
                    }`}
                  onMouseEnter={() => setHighlightSlot(slot.id)}
                  onMouseLeave={() => setHighlightSlot(null)}
                >
                  <div className="flex items-center gap-3">
                    <span className="w-7 h-7 flex-shrink-0 flex items-center justify-center rounded-md text-xs font-bold bg-[var(--color-border)] text-[var(--color-text-muted)]">
                      {slot.id}
                    </span>
                    <span className="text-xs text-[var(--color-text-muted)] w-28 flex-shrink-0 hidden sm:block">
                      {slot.label}
                    </span>
                    <select
                      value={current}
                      onChange={e => setBento(slot.id, e.target.value as WidgetType)}
                      className="flex-1 text-sm px-2 py-1.5 rounded-lg
                        bg-[var(--color-bg)] border border-[var(--color-border)]
                        text-[var(--color-text-primary)]
                        focus:outline-none focus:ring-1 focus:ring-[#6cbfd0]"
                    >
                      {WIDGET_OPTIONS.map(opt => (
                        <option key={opt.value} value={opt.value}>{opt.label}</option>
                      ))}
                    </select>
                    {current !== slot.defaultWidget && (
                      <>
                        <span className="text-[9px] text-[#6cbfd0] flex-shrink-0">✦ แก้ไว้</span>
                        <button
                          onClick={() => setBento(slot.id, slot.defaultWidget)}
                          title="คืนค่าเดิม"
                          className="text-[10px] text-[var(--color-text-muted)] hover:text-[var(--color-text-primary)] flex-shrink-0 transition-colors"
                        >
                          ↩
                        </button>
                      </>
                    )}
                  </div>
                  {/* Link inputs */}
                  {current !== 'hidden' && (
                    <div className="mt-2 ml-10 flex flex-col gap-1.5">
                      {dual ? (
                        <>
                          <div className="flex items-center gap-2">
                            <span className="w-2 h-2 rounded-full bg-[#6cbfd0] flex-shrink-0" />
                            <input
                              type="url"
                              placeholder="🔗 Link น้ำตาล (optional)"
                              value={link.namtan ?? ''}
                              onChange={e => setBentoLink(slot.id, 'namtan', e.target.value)}
                              className="flex-1 text-[11px] px-2 py-1 rounded-md
                                bg-[var(--color-bg)] border border-[var(--color-border)]
                                text-[var(--color-text-primary)] placeholder:text-[var(--color-text-muted)]/40
                                focus:outline-none focus:ring-1 focus:ring-[#6cbfd0]/50"
                            />
                          </div>
                          <div className="flex items-center gap-2">
                            <span className="w-2 h-2 rounded-full bg-[#fbdf74] flex-shrink-0" />
                            <input
                              type="url"
                              placeholder="🔗 Link ฟิล์ม (optional)"
                              value={link.film ?? ''}
                              onChange={e => setBentoLink(slot.id, 'film', e.target.value)}
                              className="flex-1 text-[11px] px-2 py-1 rounded-md
                                bg-[var(--color-bg)] border border-[var(--color-border)]
                                text-[var(--color-text-primary)] placeholder:text-[var(--color-text-muted)]/40
                                focus:outline-none focus:ring-1 focus:ring-[#fbdf74]/50"
                            />
                          </div>
                        </>
                      ) : (
                        <div className="flex items-center gap-2">
                          <span className="text-[10px] text-[var(--color-text-muted)]">🔗</span>
                          <input
                            type="url"
                            placeholder="Link (optional)"
                            value={link.single ?? ''}
                            onChange={e => setBentoLink(slot.id, 'single', e.target.value)}
                            className="flex-1 text-[11px] px-2 py-1 rounded-md
                              bg-[var(--color-bg)] border border-[var(--color-border)]
                              text-[var(--color-text-primary)] placeholder:text-[var(--color-text-muted)]/40
                              focus:outline-none focus:ring-1 focus:ring-[#6cbfd0]/50"
                          />
                        </div>
                      )}
                    </div>
                  )}
                </div>
              );
            })}
          </div>

          <button
            onClick={() => setConfig(c => ({ ...c, bento: DEFAULT_BENTO, bentoLinks: {} }))}
            className="mt-3 text-xs text-[var(--color-text-muted)] hover:text-[var(--color-text-primary)] transition-colors"
          >
            ↩ คืนค่า default ทุกช่อง (รวม link)
          </button>
        </div>

        {/* ── Stats Strip Visual Preview ────────────────────────────────── */}
        <div className="bg-[var(--color-surface)] rounded-xl border border-[var(--color-border)] overflow-hidden">
          <button
            onClick={() => setShowPreview(p => !p)}
            className="w-full flex items-center justify-between p-6 text-left hover:bg-[var(--color-border)]/10 transition-colors"
          >
            <div>
              <h2 className="text-sm font-semibold text-[var(--color-text-primary)]">
                👁 Preview — Stats Strip
              </h2>
              <p className="text-xs text-[var(--color-text-muted)] mt-0.5">
                แถบสรุปตัวเลขด้านล่าง Bento Grid
                {statsChangedCount > 0 && (
                  <span className="ml-2 text-[#6cbfd0]">({statsChangedCount} ช่องที่เปลี่ยน)</span>
                )}
              </p>
            </div>
            <span className="text-[var(--color-text-muted)] text-sm">{showPreview ? '▲' : '▼'}</span>
          </button>

          {showPreview && (
            <div className="px-6 pb-6">
              <div className="grid grid-cols-6 gap-1.5">
                {STATS_STRIP_DEFS.map(def => {
                  const tile = (config.statsStrip[def.id] ?? def.defaultTile) as StatsTileType;
                  const meta = STATS_TILE_META[tile];
                  const isHidden = tile === 'hidden';
                  const isHighlighted = highlightTile === def.id;
                  const isChanged = tile !== def.defaultTile;

                  return (
                    <div
                      key={def.id}
                      className={`rounded-lg border relative flex flex-col items-center justify-center gap-0.5 py-3 transition-all duration-200 cursor-default
                        ${isHidden
                          ? 'border-dashed border-[var(--color-border)] bg-transparent opacity-40'
                          : isHighlighted
                            ? 'border-[#6cbfd0] bg-[#6cbfd0]/10 scale-[1.03] shadow-lg shadow-[#6cbfd0]/10'
                            : 'border-[var(--color-border)] bg-[var(--color-panel)]'
                        }`}
                      onMouseEnter={() => setHighlightTile(def.id)}
                      onMouseLeave={() => setHighlightTile(null)}
                    >
                      <span className={`absolute top-1 left-1.5 text-[8px] font-bold ${isChanged ? 'text-[#6cbfd0]' : 'text-[var(--color-text-muted)]'}`}>
                        {def.id}
                      </span>
                      <span className="text-base leading-none">{meta.icon}</span>
                      <span
                        className="text-[8px] font-medium leading-tight text-center"
                        style={{ color: meta.accent ?? 'var(--color-text-secondary)' }}
                      >
                        {meta.short}
                      </span>
                      {isChanged && !isHidden && (
                        <span className="absolute top-1 right-1.5 w-1.5 h-1.5 rounded-full bg-[#6cbfd0]" />
                      )}
                    </div>
                  );
                })}
              </div>
            </div>
          )}
        </div>

        {/* ── Stats Strip Configurator ──────────────────────────────────── */}
        <div className="bg-[var(--color-surface)] rounded-xl p-6 border border-[var(--color-border)]">
          <h2 className="text-sm font-semibold text-[var(--color-text-primary)] mb-1">
            📊 Bottom Stats Strip — กำหนด Tile แต่ละช่อง
          </h2>
          <p className="text-xs text-[var(--color-text-muted)] mb-5">
            เลือกว่า Tile 1–6 ด้านล่าง Bento Grid จะแสดงข้อมูลอะไร
          </p>

          <div className="space-y-2">
            {STATS_STRIP_DEFS.map(def => {
              const current = config.statsStrip[def.id] ?? def.defaultTile;
              const isHighlighted = highlightTile === def.id;
              return (
                <div
                  key={def.id}
                  className={`flex items-center gap-3 rounded-lg px-3 py-2.5 border transition-all duration-200
                    ${isHighlighted
                      ? 'bg-[#6cbfd0]/10 border-[#6cbfd0]/40'
                      : 'bg-[var(--color-panel)] border-[var(--color-border)]'
                    }`}
                  onMouseEnter={() => setHighlightTile(def.id)}
                  onMouseLeave={() => setHighlightTile(null)}
                >
                  <span className="w-7 h-7 flex-shrink-0 flex items-center justify-center rounded-md text-xs font-bold bg-[var(--color-border)] text-[var(--color-text-muted)]">
                    {def.id}
                  </span>
                  <span className="text-xs text-[var(--color-text-muted)] w-14 flex-shrink-0 hidden sm:block">
                    {def.label}
                  </span>
                  <select
                    value={current}
                    onChange={e => setStatsTile(def.id, e.target.value as StatsTileType)}
                    className="flex-1 text-sm px-2 py-1.5 rounded-lg
                      bg-[var(--color-bg)] border border-[var(--color-border)]
                      text-[var(--color-text-primary)]
                      focus:outline-none focus:ring-1 focus:ring-[#6cbfd0]"
                  >
                    {STATS_TILE_OPTIONS.map(opt => (
                      <option key={opt.value} value={opt.value}>{opt.label}</option>
                    ))}
                  </select>
                  {current !== def.defaultTile && (
                    <>
                      <span className="text-[9px] text-[#6cbfd0] flex-shrink-0">✦ แก้ไว้</span>
                      <button
                        onClick={() => setStatsTile(def.id, def.defaultTile)}
                        title="คืนค่าเดิม"
                        className="text-[10px] text-[var(--color-text-muted)] hover:text-[var(--color-text-primary)] flex-shrink-0 transition-colors"
                      >
                        ↩
                      </button>
                    </>
                  )}
                </div>
              );
            })}
          </div>

          <button
            onClick={() => setConfig(c => ({ ...c, statsStrip: DEFAULT_STATS_STRIP }))}
            className="mt-3 text-xs text-[var(--color-text-muted)] hover:text-[var(--color-text-primary)] transition-colors"
          >
            ↩ คืนค่า default ทุก tile
          </button>
        </div>

      </div>

      {/* Save */}
      <div className="mt-6 flex items-center gap-4">
        <button
          onClick={handleSave}
          disabled={saving}
          className="px-6 py-2.5 rounded-xl text-sm font-medium bg-[#6cbfd0] text-[#141413] hover:bg-[#5aafc0] disabled:opacity-50 transition-colors"
        >
          {saving ? 'กำลังบันทึก...' : 'บันทึก'}
        </button>
        {saved && <span className="text-sm text-green-500">✓ บันทึกแล้ว</span>}
        {error && <span className="text-sm text-red-500">{error}</span>}
      </div>
    </div>
  );
}

﻿'use client';

import { useState, useEffect, useCallback } from 'react';
import Link from 'next/link';
import {
  ChevronDown, ChevronRight, Plus, Edit2, Trash2,
  Eye, EyeOff, Star, Save, X, ArrowUpRight,
} from 'lucide-react';

// ── Types ──────────────────────────────────────────────────────────────────────

type Platform = 'instagram' | 'x' | 'tiktok' | 'facebook' | 'youtube' | 'threads' | 'weibo' | 'rednote';
type Artist   = 'namtan' | 'film' | 'both';

interface MediaEvent {
  id: string;
  title: string;
  description: string | null;
  hashtags: string[];
  start_date: string | null;
  end_date: string | null;
  is_active: boolean;
  // schedule sync fields
  actors: string[];
  event_type: string;
  venue: string | null;
  link: string | null;
  content_item_id: string | null;
  brand_collab_id: number | null;
  media_posts?: MediaPost[];
}

interface MediaPost {
  id: string;
  event_id: string | null;
  platform: Platform;
  title: string | null;
  post_url: string;
  thumbnail: string | null;
  caption: string | null;
  artist: Artist;
  post_date: string;
  views: number; likes: number; comments: number; shares: number; saves: number;
  goal_views: number; goal_likes: number; goal_comments: number; goal_shares: number; goal_saves: number;
  hashtags: string[];
  is_focus: boolean;
  is_visible: boolean;
  brand_collab_id: number | null;
}

interface BrandSimple {
  id: number;
  brand_name: string;
  brand_logo: string | null;
  artists: string[];
}

// ── Constants ──────────────────────────────────────────────────────────────────

const PLATFORMS: { id: Platform; label: string; icon: string; color: string }[] = [
  { id: 'instagram', label: 'Instagram',    icon: '📸', color: 'bg-[#E4405F]/20 text-[#E4405F]' },
  { id: 'x',         label: 'X (Twitter)',  icon: '✕',  color: 'bg-sky-500/20 text-sky-400' },
  { id: 'tiktok',    label: 'TikTok',       icon: '🎵', color: 'bg-[#FF0050]/20 text-[#FF0050]' },
  { id: 'youtube',   label: 'YouTube',      icon: '▶️', color: 'bg-red-600/20 text-red-400' },
  { id: 'facebook',  label: 'Facebook',     icon: '👍', color: 'bg-blue-600/20 text-blue-400' },
  { id: 'threads',   label: 'Threads',      icon: '🧵', color: 'bg-neutral-400/20 text-neutral-300' },
  { id: 'weibo',     label: 'Weibo',        icon: '🌐', color: 'bg-orange-500/20 text-orange-400' },
  { id: 'rednote',   label: 'RedNote',      icon: '📕', color: 'bg-rose-500/20 text-rose-400' },
];
const PLATFORM_MAP = Object.fromEntries(PLATFORMS.map(p => [p.id, p]));

const ARTIST_OPTIONS = [
  { id: 'both',   label: '💙💛 คู่จิ้น' },
  { id: 'namtan', label: '💙 น้ำตาล' },
  { id: 'film',   label: '💛 ฟิล์ม' },
];

const METRICS: { icon: string; key: keyof MediaPost; goalKey: keyof MediaPost; label: string }[] = [
  { icon: '👁',  key: 'views',    goalKey: 'goal_views',    label: 'Views' },
  { icon: '❤️',  key: 'likes',    goalKey: 'goal_likes',    label: 'Likes' },
  { icon: '💬',  key: 'comments', goalKey: 'goal_comments', label: 'Comments' },
  { icon: '🔁',  key: 'shares',   goalKey: 'goal_shares',   label: 'Shares' },
  { icon: '🔖',  key: 'saves',    goalKey: 'goal_saves',    label: 'Saves' },
];

const EVENT_TYPES = [
  { id: 'event',   label: '📅 Event' },
  { id: 'show',    label: '🎬 Show' },
  { id: 'concert', label: '🎤 Concert' },
  { id: 'fanmeet', label: '💙 Fan Meet' },
  { id: 'live',    label: '📱 Live' },
  { id: 'release', label: '🎬 Release' },
];

const EMPTY_EVENT: Partial<MediaEvent> = {
  title: '', description: '', hashtags: [], start_date: null, end_date: null, is_active: true,
  actors: ['both'], event_type: 'event', venue: null, link: null, content_item_id: null,
  brand_collab_id: null,
};

const EMPTY_POST: Partial<MediaPost> = {
  platform: 'instagram', title: '', post_url: '', caption: '', artist: 'both',
  post_date: new Date().toISOString().split('T')[0],
  views: 0, likes: 0, comments: 0, shares: 0, saves: 0,
  goal_views: 0, goal_likes: 0, goal_comments: 0, goal_shares: 0, goal_saves: 0,
  hashtags: [], is_focus: false, is_visible: true,
  brand_collab_id: null,
};

const IC = 'px-3 py-2 rounded-lg bg-[var(--color-bg)] border border-[var(--color-border)] text-[var(--color-text-primary)] text-sm focus:border-[#6cbfd0] focus:outline-none';

// ── Helpers ────────────────────────────────────────────────────────────────────

function parseTags(input: string): string[] {
  return input.split(/[\s,]+/).map(t => t.trim()).filter(Boolean);
}
function fmtTags(tags: string[]): string { return tags.join(' '); }

function MetricBar({ icon, value, goal }: { icon: string; value: number; goal: number }) {
  const pct  = goal > 0 ? Math.min((value / goal) * 100, 100) : 0;
  const done = goal > 0 && value >= goal;
  return (
    <div className="space-y-0.5 min-w-0">
      <div className="flex justify-between text-[10px] gap-1">
        <span>{icon}</span>
        <span className={`tabular-nums truncate ${done ? 'text-green-400' : 'text-[var(--color-text-muted)]'}`}>
          {value.toLocaleString()}{goal > 0 ? `/${goal.toLocaleString()}` : ''}
        </span>
      </div>
      {goal > 0 && (
        <div className="h-1 bg-[var(--color-panel)] rounded-full overflow-hidden">
          <div className={`h-full rounded-full ${done ? 'bg-green-500' : 'bg-[#6cbfd0]'}`} style={{ width: `${pct}%` }} />
        </div>
      )}
    </div>
  );
}

// ── Main Component ─────────────────────────────────────────────────────────────

export default function AdminMediaPage() {
  const [events,   setEvents]  = useState<MediaEvent[]>([]);
  const [loading,  setLoading] = useState(true);
  const [error,    setError]   = useState('');
  const [expanded, setExpanded] = useState<Set<string>>(new Set());

  // Brands list for linking
  const [brands, setBrands] = useState<BrandSimple[]>([]);
  const [newBrandName, setNewBrandName] = useState('');  // inline brand creation

  // Event form state
  const [showEventForm,   setShowEventForm]   = useState(false);
  const [editingEvent,    setEditingEvent]    = useState<MediaEvent | null>(null);
  const [eventForm,       setEventForm]       = useState<Partial<MediaEvent>>(EMPTY_EVENT);
  const [eventTagsInput,  setEventTagsInput]  = useState('');

  // Post form state
  const [creatingPostFor, setCreatingPostFor] = useState<string | null>(null); // event_id
  const [editingPost,     setEditingPost]     = useState<MediaPost | null>(null);
  const [postForm,        setPostForm]        = useState<Partial<MediaPost>>(EMPTY_POST);
  const [postTagsInput,   setPostTagsInput]   = useState('');

  // ── Data fetch ──────────────────────────────────────────────────────────────

  const fetchEvents = useCallback(async () => {
    setLoading(true);
    try {
      const res = await fetch('/api/admin/media-events');
      if (!res.ok) throw new Error(await res.text());
      setEvents(await res.json());
    } catch (e: unknown) {
      setError(e instanceof Error ? e.message : 'โหลดล้มเหลว');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { fetchEvents(); }, [fetchEvents]);

  // Load brands for the link dropdown
  useEffect(() => {
    fetch('/api/brands')
      .then(r => r.json())
      .then(d => { if (Array.isArray(d?.brands)) setBrands(d.brands); })
      .catch(() => {});
  }, []);

  function toggleExpand(id: string) {
    setExpanded(prev => {
      const s = new Set(prev);
      s.has(id) ? s.delete(id) : s.add(id);
      return s;
    });
  }

  // ── Event CRUD ──────────────────────────────────────────────────────────────

  function openCreateEvent() {
    setEditingEvent(null); setEventForm(EMPTY_EVENT); setEventTagsInput('');
    setShowEventForm(true); setError('');
  }
  function openEditEvent(ev: MediaEvent) {
    setEditingEvent(ev); setEventForm({ ...ev }); setEventTagsInput(fmtTags(ev.hashtags ?? []));
    setShowEventForm(true); setError('');
  }
  function cancelEventForm() {
    setShowEventForm(false); setEditingEvent(null); setEventForm(EMPTY_EVENT);
    setEventTagsInput(''); setNewBrandName(''); setError('');
  }
  async function handleSaveEvent() {
    if (!eventForm.title?.trim()) { setError('กรุณาใส่ชื่อกิจกรรม'); return; }
    let brandId = eventForm.brand_collab_id ?? null;

    // Inline brand creation: if user typed a new brand name, create it first
    if (newBrandName.trim()) {
      const actors = eventForm.actors?.filter(a => a !== 'both') ?? [];
      const res = await fetch('/api/admin/brand-collabs', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          brand_name: newBrandName.trim(),
          artists: actors.length ? actors : ['namtan', 'film'],
          category: 'Other',
          collab_type: 'event',
          visible: true,
        }),
      });
      if (res.ok) {
        const created = await res.json();
        brandId = created.id;
        // Refresh brand list so badge appears immediately
        setBrands(prev => [...prev, { id: created.id, brand_name: created.brand_name, brand_logo: created.brand_logo ?? null, artists: created.artists ?? [] }]);
        setNewBrandName('');
      } else {
        setError('สร้างแบรนด์ล้มเหลว: ' + ((await res.json()).error ?? ''));
        return;
      }
    }

    const payload = { ...eventForm, brand_collab_id: brandId, hashtags: parseTags(eventTagsInput) };
    try {
      const res = await fetch('/api/admin/media-events', {
        method: editingEvent ? 'PUT' : 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(editingEvent ? { ...payload, id: editingEvent.id } : payload),
      });
      if (!res.ok) { setError((await res.json()).error ?? 'บันทึกล้มเหลว'); return; }
      cancelEventForm(); await fetchEvents();
    } catch { setError('เกิดข้อผิดพลาด'); }
  }
  async function handleDeleteEvent(id: string) {
    if (!confirm('ลบกิจกรรมนี้? โพสต์จะถูกยกเลิกการเชื่อมโยงแต่ไม่ถูกลบ')) return;
    await fetch(`/api/admin/media-events?id=${id}`, { method: 'DELETE' });
    await fetchEvents();
  }
  async function toggleEventActive(ev: MediaEvent) {
    await fetch('/api/admin/media-events', {
      method: 'PUT', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ id: ev.id, is_active: !ev.is_active }),
    });
    await fetchEvents();
  }

  // ── Post CRUD ───────────────────────────────────────────────────────────────

  function openCreatePost(eventId: string, eventHashtags: string[], eventBrandId?: number | null) {
    setEditingPost(null);
    setPostForm({ ...EMPTY_POST, event_id: eventId, hashtags: eventHashtags, brand_collab_id: eventBrandId ?? null });
    setPostTagsInput(fmtTags(eventHashtags));
    setCreatingPostFor(eventId); setError('');
    setExpanded(prev => new Set([...prev, eventId]));
  }
  function openEditPost(post: MediaPost) {
    setEditingPost(post); setPostForm({ ...post });
    setPostTagsInput(fmtTags(post.hashtags ?? []));
    setCreatingPostFor(null); setError('');
  }
  function cancelPostForm() {
    setCreatingPostFor(null); setEditingPost(null);
    setPostForm(EMPTY_POST); setPostTagsInput(''); setError('');
  }
  async function handleSavePost() {
    if (!postForm.post_url?.trim()) { setError('กรุณาใส่ URL'); return; }
    const payload = { ...postForm, hashtags: parseTags(postTagsInput) };
    try {
      const res = await fetch('/api/admin/media', {
        method: editingPost ? 'PUT' : 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(editingPost ? { ...payload, id: editingPost.id } : payload),
      });
      if (!res.ok) { setError((await res.json()).error ?? 'บันทึกล้มเหลว'); return; }
      cancelPostForm(); await fetchEvents();
    } catch { setError('เกิดข้อผิดพลาด'); }
  }
  async function handleDeletePost(id: string) {
    if (!confirm('ลบโพสต์นี้?')) return;
    await fetch(`/api/admin/media?id=${id}`, { method: 'DELETE' });
    await fetchEvents();
  }
  async function togglePostFlag(post: MediaPost, field: 'is_visible' | 'is_focus') {
    await fetch('/api/admin/media', {
      method: 'PUT', headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ id: post.id, [field]: !post[field] }),
    });
    await fetchEvents();
  }

  // ── Sub-forms (render functions, not components) ───────────────────────────

  function renderEventForm() {
    return (
      <div className="bg-[var(--color-surface)] border border-[var(--namtan-teal)]/40 rounded-2xl p-5 mb-6">
        <h3 className="text-base font-medium text-[var(--color-text-primary)] mb-4">
          {editingEvent ? '✏️ แก้ไขกิจกรรม' : '🎯 สร้างกิจกรรมใหม่'}
        </h3>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          {/* Brand link — at top, most prominent */}
          <div className="sm:col-span-2 space-y-1">
            <label className="text-xs text-[var(--color-text-muted)] flex items-center gap-1.5">
              🏢 เชื่อมโยงแบรนด์
              <span className="opacity-50 font-normal">— สื่อใหม่ใน event นี้จะ inherit brand อัตโนมัติ</span>
            </label>
            <div className="flex gap-2">
              <select
                className={IC + ' flex-1'}
                value={newBrandName !== '' ? '__new__' : (eventForm.brand_collab_id ?? '')}
                onChange={e => {
                  if (e.target.value === '__new__') {
                    setNewBrandName(' '); // trigger inline input (will be trimmed on save)
                    setEventForm({ ...eventForm, brand_collab_id: null });
                  } else {
                    setNewBrandName('');
                    setEventForm({ ...eventForm, brand_collab_id: e.target.value ? parseInt(e.target.value, 10) : null });
                  }
                }}
              >
                <option value="">— ไม่เชื่อมโยงกับแบรนด์ —</option>
                {brands.map(b => (
                  <option key={b.id} value={b.id}>
                    {b.brand_name}{b.artists?.length ? ` (${b.artists.join(', ')})` : ''}
                  </option>
                ))}
                <option value="__new__">➕ สร้างแบรนด์ใหม่...</option>
              </select>
            </div>
            {/* Inline new brand name input — only shown when __new__ selected */}
            {newBrandName !== '' && (
              <div className="mt-1.5">
                <input
                  type="text"
                  className={IC + ' w-full'}
                  placeholder="พิมพ์ชื่อแบรนด์ — จะสร้าง Brand Collab อัตโนมัติเมื่อบันทึก"
                  autoFocus
                  value={newBrandName.trimStart()}
                  onChange={e => setNewBrandName(e.target.value || ' ')}
                />
                {newBrandName.trim() && (
                  <p className="text-[10px] text-purple-300 mt-1">
                    ✨ จะสร้าง &ldquo;{newBrandName.trim()}&rdquo; ใน Brand Collaborations อัตโนมัติ
                  </p>
                )}
              </div>
            )}
          </div>
          <div className="sm:col-span-2 space-y-1">
            <label className="text-xs text-[var(--color-text-muted)]">ชื่อกิจกรรม *</label>
            <input type="text" className={IC} placeholder="เช่น Namtan at Prada BKK 2026"
              value={eventForm.title ?? ''}
              onChange={e => setEventForm({ ...eventForm, title: e.target.value })} />
          </div>
          <div className="sm:col-span-2 space-y-1">
            <label className="text-xs text-[var(--color-text-muted)]">คำอธิบาย (ไม่บังคับ)</label>
            <input type="text" className={IC} placeholder="รายละเอียดเพิ่มเติม"
              value={eventForm.description ?? ''}
              onChange={e => setEventForm({ ...eventForm, description: e.target.value })} />
          </div>
          {/* Schedule fields */}
          <div className="space-y-1">
            <label className="text-xs text-[var(--color-text-muted)]">ประเภทงาน</label>
            <select className={IC + ' w-full'}
              value={eventForm.event_type ?? 'event'}
              onChange={e => setEventForm({ ...eventForm, event_type: e.target.value })}>
              {EVENT_TYPES.map(t => <option key={t.id} value={t.id}>{t.label}</option>)}
            </select>
          </div>
          <div className="space-y-1">
            <label className="text-xs text-[var(--color-text-muted)]">ศิลปิน</label>
            <div className="flex gap-3 pt-2">
              {[{id:'namtan',label:'💙 น้ำตาล'},{id:'film',label:'💛 ฟิล์ม'},{id:'both',label:'💙💛 คู่จิ้น'}].map(a => (
                <label key={a.id} className="flex items-center gap-1.5 text-sm cursor-pointer">
                  <input type="checkbox" className="w-4 h-4 accent-[#6cbfd0]"
                    checked={(eventForm.actors ?? []).includes(a.id)}
                    onChange={e => {
                      const cur = eventForm.actors ?? [];
                      setEventForm({ ...eventForm, actors: e.target.checked ? [...cur.filter(x=>x!==a.id), a.id] : cur.filter(x=>x!==a.id) });
                    }} />
                  {a.label}
                </label>
              ))}
            </div>
          </div>
          <div className="space-y-1">
            <label className="text-xs text-[var(--color-text-muted)]">สถานที่ / Venue</label>
            <input type="text" className={IC + ' w-full'} placeholder="เช่น Icon Siam, Bangkok"
              value={eventForm.venue ?? ''}
              onChange={e => setEventForm({ ...eventForm, venue: e.target.value || null })} />
          </div>
          <div className="space-y-1">
            <label className="text-xs text-[var(--color-text-muted)]">ลิงก์กิจกรรม (ไม่บังคับ)</label>
            <input type="url" className={IC + ' w-full'} placeholder="https://..."
              value={eventForm.link ?? ''}
              onChange={e => setEventForm({ ...eventForm, link: e.target.value || null })} />
          </div>
          <div className="space-y-1">
            <label className="text-xs text-[var(--color-text-muted)]">วันเริ่มต้น</label>
            <input type="date" className={IC + ' w-full'}
              value={eventForm.start_date ?? ''}
              onChange={e => setEventForm({ ...eventForm, start_date: e.target.value || null })} />
          </div>
          <div className="space-y-1">
            <label className="text-xs text-[var(--color-text-muted)]">วันสิ้นสุด</label>
            <input type="date" className={IC + ' w-full'}
              value={eventForm.end_date ?? ''}
              onChange={e => setEventForm({ ...eventForm, end_date: e.target.value || null })} />
          </div>
          <div className="sm:col-span-2 space-y-1">
            <label className="text-xs text-[var(--color-text-muted)]">Hashtags ของกิจกรรม (คั่นด้วย space หรือ comma)</label>
            <textarea rows={3} className={IC + ' w-full font-mono resize-none'}
              placeholder="#namtatprada #ilonaprada2026 #prada"
              value={eventTagsInput}
              onChange={e => setEventTagsInput(e.target.value)} />
            <p className="text-[10px] text-[var(--color-text-muted)]">{parseTags(eventTagsInput).length} hashtags · จะดึงเป็น default ให้กับทุกสื่อในกิจกรรมนี้</p>
          </div>
          <div className="flex items-center gap-2 sm:col-span-2">
            <input type="checkbox" id="ev-active" className="w-4 h-4 accent-[#6cbfd0]"
              checked={eventForm.is_active !== false}
              onChange={e => setEventForm({ ...eventForm, is_active: e.target.checked })} />
            <label htmlFor="ev-active" className="text-sm text-[var(--color-text-primary)]">เปิดใช้งานกิจกรรม</label>
          </div>
        </div>
        {error && <p className="text-red-400 text-xs mt-3">{error}</p>}
        <div className="flex gap-2 mt-5 pt-4 border-t border-[var(--color-border)]">
          <button onClick={handleSaveEvent}
            className="px-5 py-2 rounded-lg bg-[#6cbfd0] text-[#141413] text-sm font-medium flex items-center gap-2 hover:bg-[#4a9aab] transition-colors">
            <Save className="w-4 h-4" /> บันทึก
          </button>
          <button onClick={cancelEventForm}
            className="px-5 py-2 rounded-lg border border-[var(--color-border)] text-[var(--color-text-muted)] text-sm flex items-center gap-2 hover:text-[var(--color-text-primary)] transition-colors">
            <X className="w-4 h-4" /> ยกเลิก
          </button>
        </div>
      </div>
    );
  }

  function renderPostForm() {
    return (
      <div className="bg-[var(--color-surface)] border border-[var(--color-border)] rounded-xl p-4 mb-3">
        <h4 className="text-sm font-medium text-[var(--color-text-primary)] mb-4">
          {editingPost ? '✏️ แก้ไขสื่อ' : '➕ เพิ่มสื่อใหม่'}
        </h4>
        <div className="grid grid-cols-2 sm:grid-cols-4 gap-3">
          <div className="space-y-1">
            <label className="text-xs text-[var(--color-text-muted)]">แพลตฟอร์ม</label>
            <select className={IC + ' w-full'}
              value={postForm.platform ?? 'instagram'}
              onChange={e => setPostForm({ ...postForm, platform: e.target.value as Platform })}>
              {PLATFORMS.map(p => <option key={p.id} value={p.id}>{p.icon} {p.label}</option>)}
            </select>
          </div>
          <div className="space-y-1">
            <label className="text-xs text-[var(--color-text-muted)]">ศิลปิน</label>
            <select className={IC + ' w-full'}
              value={postForm.artist ?? 'both'}
              onChange={e => setPostForm({ ...postForm, artist: e.target.value as Artist })}>
              {ARTIST_OPTIONS.map(a => <option key={a.id} value={a.id}>{a.label}</option>)}
            </select>
          </div>
          <div className="space-y-1 col-span-2">
            <label className="text-xs text-[var(--color-text-muted)]">ชื่อสื่อ (ไม่บังคับ)</label>
            <input type="text" className={IC + ' w-full'} placeholder="เช่น ลุคที่1 งาน Prada"
              value={postForm.title ?? ''}
              onChange={e => setPostForm({ ...postForm, title: e.target.value })} />
          </div>
          <div className="col-span-2 sm:col-span-3 space-y-1">
            <label className="text-xs text-[var(--color-text-muted)]">URL *</label>
            <input type="url" className={IC + ' w-full'} placeholder="https://..."
              value={postForm.post_url ?? ''}
              onChange={e => setPostForm({ ...postForm, post_url: e.target.value })} />
          </div>
          <div className="space-y-1">
            <label className="text-xs text-[var(--color-text-muted)]">วันที่โพสต์</label>
            <input type="date" className={IC + ' w-full'}
              value={postForm.post_date ? postForm.post_date.split('T')[0] : ''}
              onChange={e => setPostForm({ ...postForm, post_date: e.target.value })} />
          </div>
          <div className="col-span-2 sm:col-span-4 space-y-1">
            <label className="text-xs text-[var(--color-text-muted)]">Caption</label>
            <textarea rows={2} className={IC + ' w-full resize-none'} placeholder="ข้อความในโพสต์..."
              value={postForm.caption ?? ''}
              onChange={e => setPostForm({ ...postForm, caption: e.target.value })} />
          </div>

          {/* Engagement & Goals */}
          <div className="col-span-2 sm:col-span-4">
            <p className="text-xs text-[var(--color-text-muted)] mb-2">Engagement & เป้าหมาย <span className="opacity-60">(บน = ยอดจริง · ล่าง = เป้าหมาย)</span></p>
            <div className="grid grid-cols-5 gap-2">
              {METRICS.map(({ icon, key, goalKey, label }) => (
                <div key={String(key)} className="space-y-1">
                  <label className="text-[10px] text-[var(--color-text-muted)] flex items-center gap-1">{icon} {label}</label>
                  <input type="number" min={0} placeholder="0" className={IC + ' w-full text-xs py-1.5'}
                    value={(postForm as Record<string, unknown>)[key as string] as number ?? 0}
                    onChange={e => setPostForm({ ...postForm, [key]: parseInt(e.target.value) || 0 })} />
                  <input type="number" min={0} placeholder="เป้า" className={`${IC} w-full text-xs py-1.5 border-dashed opacity-70`}
                    value={(postForm as Record<string, unknown>)[goalKey as string] as number ?? 0}
                    onChange={e => setPostForm({ ...postForm, [goalKey]: parseInt(e.target.value) || 0 })} />
                </div>
              ))}
            </div>
          </div>

          {/* Hashtags */}
          <div className="col-span-2 sm:col-span-4 space-y-1">
            <label className="text-xs text-[var(--color-text-muted)]">Hashtags <span className="opacity-60">(ดึงมาจากกิจกรรม — แก้ไขได้)</span></label>
            <textarea rows={2} className={IC + ' w-full font-mono text-xs resize-none'}
              value={postTagsInput}
              onChange={e => setPostTagsInput(e.target.value)} />
            <p className="text-[10px] text-[var(--color-text-muted)]">{parseTags(postTagsInput).length} hashtags</p>
          </div>

          {/* Flags */}
          <div className="col-span-2 sm:col-span-4 flex items-center gap-5">
            <label className="flex items-center gap-2 text-sm cursor-pointer">
              <input type="checkbox" className="w-4 h-4 accent-amber-400"
                checked={postForm.is_focus === true}
                onChange={e => setPostForm({ ...postForm, is_focus: e.target.checked })} />
              <Star className="w-3.5 h-3.5 text-amber-400" /> Focus (อันดับ 1)
            </label>
            <label className="flex items-center gap-2 text-sm cursor-pointer">
              <input type="checkbox" className="w-4 h-4 accent-[#6cbfd0]"
                checked={postForm.is_visible !== false}
                onChange={e => setPostForm({ ...postForm, is_visible: e.target.checked })} />
              <Eye className="w-3.5 h-3.5" /> แสดงผล
            </label>
          </div>

          {/* Brand link */}
          <div className="col-span-2 sm:col-span-4 space-y-1">
            <label className="text-xs text-[var(--color-text-muted)] flex items-center gap-1.5">
              🏢 เชื่อมโยงแบรนด์
              <span className="opacity-50 font-normal">— สื่อนี้จะถูก sync อัตโนมัติไปยัง Brand Collaborations</span>
            </label>
            <select
              className={IC + ' w-full'}
              value={postForm.brand_collab_id ?? ''}
              onChange={e => setPostForm({
                ...postForm,
                brand_collab_id: e.target.value ? parseInt(e.target.value, 10) : null,
              })}
            >
              <option value="">— ไม่เชื่อมโยงกับแบรนด์ —</option>
              {brands.map(b => (
                <option key={b.id} value={b.id}>
                  {b.brand_name}
                  {b.artists?.length ? ` (${b.artists.join(', ')})` : ''}
                </option>
              ))}
            </select>
          </div>
        </div>
        {error && <p className="text-red-400 text-xs mt-3">{error}</p>}
        <div className="flex gap-2 mt-4 pt-4 border-t border-[var(--color-border)]">
          <button onClick={handleSavePost}
            className="px-4 py-2 rounded-lg bg-[#6cbfd0] text-[#141413] text-sm font-medium flex items-center gap-2 hover:bg-[#4a9aab] transition-colors">
            <Save className="w-4 h-4" /> บันทึก
          </button>
          <button onClick={cancelPostForm}
            className="px-4 py-2 rounded-lg border border-[var(--color-border)] text-[var(--color-text-muted)] text-sm flex items-center gap-2 hover:text-[var(--color-text-primary)] transition-colors">
            <X className="w-4 h-4" /> ยกเลิก
          </button>
        </div>
      </div>
    );
  }

  // ── Render ──────────────────────────────────────────────────────────────────

  return (
    <div className="max-w-5xl mx-auto px-6 py-8">

      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-start justify-between mb-6 pb-4 border-b border-[var(--color-border)] gap-4">
        <div>
          <Link href="/admin/dashboard"
            className="text-sm text-[var(--color-text-muted)] hover:text-[var(--color-text-primary)] flex items-center gap-1.5 w-fit mb-1">
            ← Dashboard
          </Link>
          <h1 className="font-display text-2xl font-medium text-[var(--color-text-primary)] flex items-center gap-2">
            🎞️ Media & Engagement
          </h1>
          <p className="text-sm text-[var(--color-text-muted)]">จัดการกิจกรรมและสื่อโซเชียลมีเดีย</p>
        </div>
        {!showEventForm && (
          <button onClick={openCreateEvent}
            className="px-4 py-2 rounded-xl bg-[#6cbfd0] text-[#141413] font-medium text-sm flex items-center gap-1.5 hover:bg-[#4a9aab] transition-colors shrink-0">
            <Plus className="w-4 h-4" /> สร้างกิจกรรม
          </button>
        )}
      </div>

      {/* Event Form */}
      {showEventForm && renderEventForm()}

      {/* Loading */}
      {loading && <div className="text-center py-16 text-[var(--color-text-muted)]">กำลังโหลด...</div>}

      {/* Empty state */}
      {!loading && events.length === 0 && !showEventForm && (
        <div className="text-center py-20 border border-[var(--color-border)] rounded-2xl border-dashed text-[var(--color-text-muted)]">
          <p className="text-5xl mb-3">🎯</p>
          <p className="text-sm mb-1 font-medium">ยังไม่มีกิจกรรม</p>
          <p className="text-xs">กดปุ่ม &quot;สร้างกิจกรรม&quot; ด้านบนเพื่อเริ่มต้น</p>
        </div>
      )}

      {/* Events list */}
      <div className="space-y-4">
        {events.map(ev => {
          const isOpen  = expanded.has(ev.id);
          const posts   = ev.media_posts ?? [];
          const focused = posts.filter(p => p.is_focus).length;

          return (
            <div key={ev.id}
              className={`bg-[var(--color-surface)] border rounded-2xl overflow-hidden ${
                ev.is_active ? 'border-[var(--color-border)]' : 'border-[var(--color-border)] opacity-60'
              }`}>

              {/* Event Header Row */}
              <div className="flex items-start gap-3 px-4 py-4">
                <button onClick={() => toggleExpand(ev.id)}
                  className="mt-0.5 text-[var(--color-text-muted)] hover:text-[var(--color-text-primary)] transition-colors shrink-0">
                  {isOpen
                    ? <ChevronDown className="w-4 h-4" />
                    : <ChevronRight className="w-4 h-4" />}
                </button>

                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2 flex-wrap">
                    <span className="font-medium text-[var(--color-text-primary)]">{ev.title}</span>
                    <span className={`text-[10px] px-2 py-0.5 rounded-full ${
                      ev.is_active
                        ? 'bg-green-500/20 text-green-400'
                        : 'bg-[var(--color-panel)] text-[var(--color-text-muted)]'
                    }`}>{ev.is_active ? '● active' : '○ inactive'}</span>
                    <span className="text-[10px] bg-[var(--color-panel)] text-[var(--color-text-muted)] px-2 py-0.5 rounded-full">
                      {posts.length} สื่อ{focused > 0 ? ` · ⭐ ${focused} focus` : ''}
                    </span>
                    {ev.brand_collab_id && (() => {
                      const b = brands.find(x => x.id === ev.brand_collab_id);
                      return b ? (
                        <span className="text-[10px] bg-purple-500/15 text-purple-300 px-2 py-0.5 rounded-full border border-purple-500/25">
                          🏢 {b.brand_name}
                        </span>
                      ) : null;
                    })()}
                  </div>
                  {(ev.start_date || ev.end_date) && (
                    <p className="text-xs text-[var(--color-text-muted)] mt-0.5">
                      📅 {ev.start_date ?? '?'} → {ev.end_date ?? '?'}
                    </p>
                  )}
                  {ev.description && (
                    <p className="text-xs text-[var(--color-text-muted)] mt-0.5">{ev.description}</p>
                  )}
                  {(ev.hashtags?.length ?? 0) > 0 && (
                    <div className="flex flex-wrap gap-1 mt-2">
                      {ev.hashtags.slice(0, 7).map(tag => (
                        <span key={tag} className="text-[10px] bg-[#6cbfd0]/10 text-[#6cbfd0] px-1.5 py-0.5 rounded border border-[#6cbfd0]/20">
                          {tag}
                        </span>
                      ))}
                      {ev.hashtags.length > 7 && (
                        <span className="text-[10px] text-[var(--color-text-muted)]">+{ev.hashtags.length - 7}</span>
                      )}
                    </div>
                  )}
                </div>

                {/* Event Actions */}
                <div className="flex items-center gap-2 shrink-0">
                  {!creatingPostFor && !editingPost && (
                    <button
                      onClick={() => { openCreatePost(ev.id, ev.hashtags ?? [], ev.brand_collab_id); setExpanded(prev => new Set([...prev, ev.id])); }}
                      className="px-3 py-1.5 rounded-lg bg-[#6cbfd0]/15 border border-[#6cbfd0]/40 text-[#6cbfd0] text-xs font-medium flex items-center gap-1.5 hover:bg-[#6cbfd0]/25 transition-colors">
                      <Plus className="w-3.5 h-3.5" /> เพิ่มสื่อ
                    </button>
                  )}
                  <button onClick={() => toggleEventActive(ev)}
                    title={ev.is_active ? 'ปิดกิจกรรม' : 'เปิดกิจกรรม'}
                    className={`p-1.5 rounded-lg transition-colors ${
                      ev.is_active
                        ? 'text-green-400 hover:bg-green-400/10'
                        : 'text-[var(--color-text-muted)] hover:bg-[var(--color-panel)]'
                    }`}>
                    {ev.is_active ? <Eye className="w-4 h-4" /> : <EyeOff className="w-4 h-4" />}
                  </button>
                  <button onClick={() => openEditEvent(ev)}
                    className="p-1.5 text-[var(--color-text-muted)] hover:text-[var(--color-text-primary)] hover:bg-[var(--color-panel)] rounded-lg transition-colors">
                    <Edit2 className="w-4 h-4" />
                  </button>
                  <button onClick={() => handleDeleteEvent(ev.id)}
                    className="p-1.5 text-red-400/60 hover:text-red-400 hover:bg-red-400/10 rounded-lg transition-colors">
                    <Trash2 className="w-4 h-4" />
                  </button>
                </div>
              </div>

              {/* Posts Panel (expanded) */}
              {isOpen && (
                <div className="border-t border-[var(--color-border)] px-4 py-3 space-y-2 bg-[var(--color-bg)]/30">

                  {/* Post form (create or edit within this event) */}
                  {(creatingPostFor === ev.id ||
                    (editingPost && editingPost.event_id === ev.id)) &&
                    renderPostForm()}

                  {/* Empty posts */}
                  {posts.length === 0 && creatingPostFor !== ev.id && !editingPost && (
                    <p className="text-xs text-[var(--color-text-muted)] text-center py-4">
                      ยังไม่มีสื่อ — กดปุ่ม &quot;+ เพิ่มสื่อ&quot; ด้านล่าง
                    </p>
                  )}

                  {/* Post list */}
                  {posts.map(post => {
                    const plat     = PLATFORM_MAP[post.platform];
                    const hasGoals = METRICS.some(m => (post[m.goalKey] as number) > 0);
                    const isEditingThis = editingPost?.id === post.id;

                    if (isEditingThis) return null; // form shown above

                    return (
                      <div key={post.id}
                        className={`bg-[var(--color-surface)] border border-[var(--color-border)] rounded-xl p-3 ${
                          !post.is_visible ? 'opacity-50' : ''
                        }`}>
                        <div className="flex items-start gap-3">
                          {/* Platform icon */}
                          <div className={`w-8 h-8 rounded-full flex items-center justify-center text-sm shrink-0 ${plat?.color ?? 'bg-neutral-500/20 text-neutral-300'}`}>
                            {plat?.icon ?? '📱'}
                          </div>

                          <div className="flex-1 min-w-0">
                            {/* Badges row */}
                            <div className="flex items-center gap-1.5 flex-wrap mb-0.5">
                              <span className={`text-[10px] px-1.5 py-0.5 rounded-full font-medium ${plat?.color}`}>{plat?.label}</span>
                              {post.title && (
                                <span className="text-sm font-medium text-[var(--color-text-primary)]">{post.title}</span>
                              )}
                              {post.is_focus && (
                                <span className="text-[10px] bg-amber-500/20 text-amber-400 px-1.5 py-0.5 rounded-full flex items-center gap-0.5">
                                  <Star className="w-2.5 h-2.5 fill-amber-400" /> Focus
                                </span>
                              )}
                              {!post.is_visible && (
                                <span className="text-[10px] bg-red-500/20 text-red-400 px-1.5 py-0.5 rounded-full">ซ่อน</span>
                              )}
                              {post.brand_collab_id && (() => {
                                const b = brands.find(x => x.id === post.brand_collab_id);
                                return b ? (
                                  <span className="text-[10px] bg-purple-500/15 text-purple-300 px-1.5 py-0.5 rounded-full border border-purple-500/25 flex items-center gap-0.5">
                                    🏢 {b.brand_name}
                                  </span>
                                ) : null;
                              })()}
                            </div>

                            {post.caption && (
                              <p className="text-xs text-[var(--color-text-muted)] line-clamp-1 mb-1.5">{post.caption}</p>
                            )}

                            {/* Metrics */}
                            {hasGoals ? (
                              <div className="grid grid-cols-5 gap-2 mt-1">
                                {METRICS.map(({ icon, key, goalKey }) => (
                                  <MetricBar key={String(key)} icon={icon}
                                    value={(post[key] as number) ?? 0}
                                    goal={(post[goalKey] as number) ?? 0} />
                                ))}
                              </div>
                            ) : (
                              <p className="text-xs text-[var(--color-text-muted)] tabular-nums">
                                👁 {(post.views ?? 0).toLocaleString()} · ❤️ {(post.likes ?? 0).toLocaleString()} · 💬 {(post.comments ?? 0).toLocaleString()} · 🔁 {(post.shares ?? 0).toLocaleString()} · 🔖 {(post.saves ?? 0).toLocaleString()}
                              </p>
                            )}

                            {/* Hashtags preview */}
                            {(post.hashtags?.length ?? 0) > 0 && (
                              <div className="flex flex-wrap gap-1 mt-1.5">
                                {post.hashtags.slice(0, 4).map(t => (
                                  <span key={t} className="text-[9px] px-1.5 py-0.5 bg-black/20 text-neutral-400 rounded border border-white/5">{t}</span>
                                ))}
                                {post.hashtags.length > 4 && (
                                  <span className="text-[9px] text-[var(--color-text-muted)]">+{post.hashtags.length - 4}</span>
                                )}
                              </div>
                            )}
                          </div>

                          {/* Post actions */}
                          <div className="flex items-center gap-1 shrink-0">
                            <a href={post.post_url} target="_blank" rel="noreferrer"
                              className="p-1.5 text-[#6cbfd0] hover:bg-[#6cbfd0]/10 rounded-lg transition-colors" title="เปิด URL">
                              <ArrowUpRight className="w-4 h-4" />
                            </a>
                            <button onClick={() => togglePostFlag(post, 'is_focus')}
                              title={post.is_focus ? 'ยกเลิก Focus' : 'ตั้งเป็น Focus'}
                              className={`p-1.5 rounded-lg transition-colors ${
                                post.is_focus
                                  ? 'text-amber-400 hover:bg-amber-400/10'
                                  : 'text-[var(--color-text-muted)] hover:bg-[var(--color-panel)]'
                              }`}>
                              <Star className={`w-4 h-4 ${post.is_focus ? 'fill-amber-400' : ''}`} />
                            </button>
                            <button onClick={() => togglePostFlag(post, 'is_visible')}
                              title={post.is_visible ? 'ซ่อน' : 'แสดง'}
                              className={`p-1.5 rounded-lg transition-colors ${
                                post.is_visible
