    education: 'Srinakharinwirot University (Faculty of Fine Arts)',
    education_th: 'มหาวิทยาลัยศรีนครินทรวิโรฒ (คณะศิลปกรรมศาสตร์)',
    instagram: 'namtan.tipnaree',
    twitter: 'NamtanTipnaree',
  },
  {
