    birth_place: 'Bangkok, Thailand',
    birth_place_th: 'กรุงเทพมหานคร ประเทศไทย',
    education: 'King Mongkut\'s University of Technology Thonburi',
    education_th: 'มหาวิทยาลัยเทคโนโลยีพระจอมเกล้าธนบุรี',
