'use client';

import { useState, useEffect, useCallback } from 'react';
import Link from 'next/link';
import { Plus, Trash2, RefreshCw, TrendingUp } from 'lucide-react';

type Artist   = 'namtan' | 'film' | 'luna';
type Platform = 'ig' | 'x' | 'tiktok' | 'weibo';

interface Snapshot {
  id: number;
  artist: Artist;
  platform: Platform;
  followers: number;
  recorded_date: string;
  note: string | null;
  created_at: string;
}

const ARTISTS: { value: Artist; label: string; color: string }[] = [
  { value: 'namtan', label: '💙 น้ำตาล', color: '#6cbfd0' },
  { value: 'film',   label: '💛 ฟิล์ม',  color: '#fbdf74' },
  { value: 'luna',   label: '💜 ลูน่า',  color: '#c084fc' },
];

const PLATFORMS: { value: Platform; label: string; icon: string }[] = [
  { value: 'ig',     label: 'Instagram', icon: '📸' },
  { value: 'x',      label: 'X',         icon: '𝕏'  },
  { value: 'tiktok', label: 'TikTok',    icon: '🎵' },
  { value: 'weibo',  label: 'Weibo',     icon: '🌐' },
];

const ARTIST_LABELS: Record<Artist, string>   = { namtan: '💙 น้ำตาล', film: '💛 ฟิล์ม', luna: '💜 ลูน่า' };
const PLATFORM_LABELS: Record<Platform, string> = { ig: '📸 IG', x: '𝕏 X', tiktok: '🎵 TikTok', weibo: '🌐 Weibo' };

const EMPTY_FORM = {
  artist:        'namtan' as Artist,
  platform:      'ig'     as Platform,
  followers:     '',
  recorded_date: new Date().toISOString().split('T')[0],
  note:          '',
};

export default function FollowerSnapshotsPage() {
  const [snapshots, setSnapshots]     = useState<Snapshot[]>([]);
  const [loading, setLoading]         = useState(true);
  const [saving, setSaving]           = useState(false);
  const [msg, setMsg]                 = useState<{ text: string; ok: boolean } | null>(null);
  const [showForm, setShowForm]       = useState(false);
  const [form, setForm]               = useState({ ...EMPTY_FORM });
  const [filterArtist, setFilterArtist]     = useState<Artist | 'all'>('all');
  const [filterPlatform, setFilterPlatform] = useState<Platform | 'all'>('all');

  const flash = (text: string, ok: boolean) => {
    setMsg({ text, ok });
    setTimeout(() => setMsg(null), 4000);
  };

  const fetchSnapshots = useCallback(async () => {
    setLoading(true);
    try {
      const params = new URLSearchParams({ limit: '200' });
      if (filterArtist   !== 'all') params.set('artist', filterArtist);
      if (filterPlatform !== 'all') params.set('platform', filterPlatform);
      const data = await fetch(`/api/admin/follower-snapshots?${params}`).then(r => r.json());
      if (Array.isArray(data)) setSnapshots(data);
    } catch { flash('โหลดข้อมูลล้มเหลว', false); }
    finally { setLoading(false); }
  }, [filterArtist, filterPlatform]);

  useEffect(() => { fetchSnapshots(); }, [fetchSnapshots]);

  const handleSave = async () => {
    if (!form.followers || isNaN(Number(form.followers))) {
      flash('กรุณากรอกจำนวนผู้ติดตามที่ถูกต้อง', false);
      return;
    }
    setSaving(true);
    try {
      const res  = await fetch('/api/admin/follower-snapshots', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ...form, followers: Number(form.followers) }),
      });
      const data = await res.json();
      if (!res.ok) { flash(data.error ?? 'บันทึกไม่สำเร็จ', false); return; }
      flash('บันทึกสำเร็จ', true);
      setShowForm(false);
      setForm({ ...EMPTY_FORM });
      fetchSnapshots();
    } catch { flash('Network error', false); }
    finally { setSaving(false); }
  };

  const handleDelete = async (id: number) => {
    if (!confirm('ลบข้อมูลนี้?')) return;
    try {
      const res = await fetch(`/api/admin/follower-snapshots?id=${id}`, { method: 'DELETE' });
      if (!res.ok) { flash('ลบไม่สำเร็จ', false); return; }
      flash('ลบสำเร็จ', true);
      setSnapshots(prev => prev.filter(s => s.id !== id));
    } catch { flash('Network error', false); }
  };

  const formatNum = (n: number) =>
    n >= 1_000_000 ? `${(n / 1_000_000).toFixed(2)}M`
    : n >= 1_000   ? `${(n / 1_000).toFixed(1)}K`
    : `${n}`;

  return (
    <div className="max-w-5xl mx-auto px-6 py-8">

      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-start justify-between mb-8 pb-4 border-b border-[var(--color-border)] gap-4">
        <div className="flex flex-col gap-1">
          <Link href="/admin/social-stats" className="text-sm text-[var(--color-text-muted)] hover:text-[var(--color-text-primary)] flex items-center gap-1.5 w-fit transition-colors">
            ← Social Stats
          </Link>
          <h1 className="font-display text-2xl font-normal text-[var(--color-text-primary)] flex items-center gap-2">
            <TrendingUp className="w-6 h-6 text-[#6cbfd0]" /> ประวัติยอดผู้ติดตาม
          </h1>
          <p className="text-sm text-[var(--color-text-muted)]">บันทึกยอดฟอลโลเวอร์รายวัน แยกตามศิลปินและแพลตฟอร์ม</p>
        </div>
        <div className="flex gap-2 shrink-0">
          <button onClick={fetchSnapshots} disabled={loading} className="px-4 py-2 rounded-xl border border-[var(--color-border)] text-sm text-[var(--color-text-muted)] hover:text-[var(--color-text-primary)] flex items-center gap-2 transition-colors disabled:opacity-50">
            <RefreshCw className={`w-4 h-4 ${loading ? 'animate-spin' : ''}`} /> รีเฟรช
          </button>
          <button onClick={() => { setShowForm(true); setForm({ ...EMPTY_FORM }); }} className="px-4 py-2 rounded-xl bg-[#6cbfd0] text-[#141413] text-sm font-medium flex items-center gap-2 hover:opacity-90 transition-opacity">
            <Plus className="w-4 h-4" /> บันทึกยอดใหม่
          </button>
        </div>
      </div>

      {/* Flash message */}
      {msg && (
        <div className={`mb-6 px-4 py-3 rounded-xl border text-sm font-medium ${msg.ok ? 'bg-green-500/10 border-green-500/30 text-green-400' : 'bg-red-500/10 border-red-500/30 text-red-400'}`}>
          {msg.ok ? '✅' : '❌'} {msg.text}
        </div>
      )}

      {/* Add form */}
      {showForm && (
        <div className="mb-6 bg-[var(--color-surface)] border border-[var(--color-border)] rounded-xl p-5">
          <h2 className="text-sm font-normal text-[var(--color-text-primary)] mb-4">บันทึกยอดผู้ติดตามใหม่</h2>
          <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
            {/* Artist */}
            <div>
              <label className="block text-xs text-[var(--color-text-muted)] mb-1">ศิลปิน *</label>
              <select value={form.artist} onChange={e => setForm(f => ({ ...f, artist: e.target.value as Artist }))}
                className="w-full bg-[var(--color-bg)] border border-[var(--color-border)] rounded-lg px-3 py-2 text-sm text-[var(--color-text-primary)] focus:outline-none focus:border-[#6cbfd0]">
                {ARTISTS.map(a => <option key={a.value} value={a.value}>{a.label}</option>)}
              </select>
            </div>
            {/* Platform */}
            <div>
              <label className="block text-xs text-[var(--color-text-muted)] mb-1">แพลตฟอร์ม *</label>
              <select value={form.platform} onChange={e => setForm(f => ({ ...f, platform: e.target.value as Platform }))}
                className="w-full bg-[var(--color-bg)] border border-[var(--color-border)] rounded-lg px-3 py-2 text-sm text-[var(--color-text-primary)] focus:outline-none focus:border-[#6cbfd0]">
                {PLATFORMS.map(p => <option key={p.value} value={p.value}>{p.icon} {p.label}</option>)}
              </select>
            </div>
            {/* Date */}
            <div>
              <label className="block text-xs text-[var(--color-text-muted)] mb-1">วันที่บันทึก *</label>
              <input type="date" value={form.recorded_date} onChange={e => setForm(f => ({ ...f, recorded_date: e.target.value }))}
                className="w-full bg-[var(--color-bg)] border border-[var(--color-border)] rounded-lg px-3 py-2 text-sm text-[var(--color-text-primary)] focus:outline-none focus:border-[#6cbfd0]" />
            </div>
            {/* Followers */}
            <div>
              <label className="block text-xs text-[var(--color-text-muted)] mb-1">จำนวนผู้ติดตาม *</label>
              <input type="number" min="0" value={form.followers} onChange={e => setForm(f => ({ ...f, followers: e.target.value }))}
                placeholder="เช่น 125000"
                className="w-full bg-[var(--color-bg)] border border-[var(--color-border)] rounded-lg px-3 py-2 text-sm text-[var(--color-text-primary)] focus:outline-none focus:border-[#6cbfd0]" />
            </div>
            {/* Note */}
            <div className="md:col-span-2">
              <label className="block text-xs text-[var(--color-text-muted)] mb-1">หมายเหตุ</label>
              <input type="text" value={form.note} onChange={e => setForm(f => ({ ...f, note: e.target.value }))}
                placeholder="เช่น หลังออกซีรีส์ EP5"
                className="w-full bg-[var(--color-bg)] border border-[var(--color-border)] rounded-lg px-3 py-2 text-sm text-[var(--color-text-primary)] focus:outline-none focus:border-[#6cbfd0]" />
            </div>
          </div>
          <div className="flex gap-3 mt-4">
            <button onClick={handleSave} disabled={saving}
              className="px-5 py-2 rounded-xl bg-[#6cbfd0] text-[#141413] text-sm font-medium hover:opacity-90 disabled:opacity-50 transition-opacity">
              {saving ? 'กำลังบันทึก...' : 'บันทึก'}
            </button>
            <button onClick={() => setShowForm(false)} className="px-5 py-2 rounded-xl border border-[var(--color-border)] text-sm text-[var(--color-text-muted)] hover:text-[var(--color-text-primary)] transition-colors">
              ยกเลิก
            </button>
          </div>
        </div>
      )}

      {/* Filters */}
      <div className="flex flex-wrap gap-3 mb-5">
        <div className="flex items-center gap-2">
          <span className="text-xs text-[var(--color-text-muted)]">ศิลปิน:</span>
          <div className="flex gap-1">
            {[{ value: 'all', label: 'ทั้งหมด' }, ...ARTISTS.map(a => ({ value: a.value, label: a.label }))].map(opt => (
              <button key={opt.value} onClick={() => setFilterArtist(opt.value as Artist | 'all')}
                className={`px-3 py-1 rounded-lg text-xs font-medium transition-all ${filterArtist === opt.value ? 'bg-[#6cbfd0] text-[#141413]' : 'border border-[var(--color-border)] text-[var(--color-text-muted)] hover:text-[var(--color-text-primary)]'}`}>
                {opt.label}
              </button>
            ))}
          </div>
        </div>
        <div className="flex items-center gap-2">
          <span className="text-xs text-[var(--color-text-muted)]">แพลตฟอร์ม:</span>
          <div className="flex gap-1">
            {[{ value: 'all', label: 'ทั้งหมด' }, ...PLATFORMS.map(p => ({ value: p.value, label: p.icon + ' ' + p.label }))].map(opt => (
              <button key={opt.value} onClick={() => setFilterPlatform(opt.value as Platform | 'all')}
                className={`px-3 py-1 rounded-lg text-xs font-medium transition-all ${filterPlatform === opt.value ? 'bg-[#6cbfd0] text-[#141413]' : 'border border-[var(--color-border)] text-[var(--color-text-muted)] hover:text-[var(--color-text-primary)]'}`}>
                {opt.label}
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Table */}
      <div className="bg-[var(--color-surface)] border border-[var(--color-border)] rounded-xl overflow-hidden">
        {loading ? (
          <div className="flex items-center justify-center h-40 text-[var(--color-text-muted)] text-sm">กำลังโหลด...</div>
        ) : snapshots.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-40 gap-2 text-[var(--color-text-muted)]">
            <span className="text-3xl">📭</span>
            <span className="text-sm">ยังไม่มีข้อมูล</span>
            <button onClick={() => setShowForm(true)} className="mt-1 text-xs text-[#6cbfd0] hover:underline">+ บันทึกยอดแรก</button>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full">
              <thead>
                <tr className="border-b border-[var(--color-border)] bg-[var(--color-panel)]">
                  <th className="text-left px-4 py-3 text-xs font-semibold text-[var(--color-text-muted)] uppercase tracking-wider">วันที่</th>
                  <th className="text-left px-4 py-3 text-xs font-semibold text-[var(--color-text-muted)] uppercase tracking-wider">ศิลปิน</th>
                  <th className="text-left px-4 py-3 text-xs font-semibold text-[var(--color-text-muted)] uppercase tracking-wider">แพลตฟอร์ม</th>
                  <th className="text-right px-4 py-3 text-xs font-semibold text-[var(--color-text-muted)] uppercase tracking-wider">ผู้ติดตาม</th>
                  <th className="text-left px-4 py-3 text-xs font-semibold text-[var(--color-text-muted)] uppercase tracking-wider">หมายเหตุ</th>
                  <th className="px-4 py-3" />
                </tr>
              </thead>
              <tbody className="divide-y divide-[var(--color-border)]">
                {snapshots.map(s => (
                  <tr key={s.id} className="hover:bg-[var(--color-panel)] transition-colors">
                    <td className="px-4 py-3 text-sm text-[var(--color-text-primary)] tabular-nums">{s.recorded_date}</td>
                    <td className="px-4 py-3 text-sm">{ARTIST_LABELS[s.artist]}</td>
                    <td className="px-4 py-3 text-sm text-[var(--color-text-secondary)]">{PLATFORM_LABELS[s.platform]}</td>
                    <td className="px-4 py-3 text-sm text-right font-medium text-[var(--color-text-primary)] tabular-nums">
                      {s.followers.toLocaleString('th-TH')}
                      <span className="text-[10px] text-[var(--color-text-muted)] ml-1">({formatNum(s.followers)})</span>
                    </td>
                    <td className="px-4 py-3 text-sm text-[var(--color-text-muted)] max-w-[200px] truncate">{s.note ?? '—'}</td>
                    <td className="px-4 py-3 text-right">
                      <button onClick={() => handleDelete(s.id)} className="p-1.5 rounded-lg text-[var(--color-text-muted)] hover:text-red-400 hover:bg-red-400/10 transition-colors">
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
            <div className="px-4 py-2 border-t border-[var(--color-border)] text-xs text-[var(--color-text-muted)]">
              {snapshots.length} รายการ
            </div>
          </div>
        )}
      </div>
    </div>
  );
}

'use client';

import { useState, useEffect } from 'react';
import Link from 'next/link';
import { TimelineEvent } from '@/data/timeline';

// Map snake_case API response → camelCase TimelineEvent
function fromApi(row: unknown): TimelineEvent {
  return { ...row, titleThai: row.title_thai ?? '' };
}
// Map camelCase TimelineEvent → snake_case for API
function toApi(evt: Partial<TimelineEvent>): unknown {
  const { titleThai, ...rest } = evt as unknown;
  return { ...rest, title_thai: titleThai };
}

export default function AdminTimelinePage() {
  const [events, setEvents] = useState<TimelineEvent[]>([]);
  const [loading, setLoading] = useState(true);
  const [isCreating, setIsCreating] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editForm, setEditForm] = useState<Partial<TimelineEvent>>({});
  const [saveMsg, setSaveMsg] = useState('');

  useEffect(() => {
    fetch('/api/admin/timeline')
      .then(r => r.json())
      .then(data => {
        if (Array.isArray(data)) setEvents(data.map(fromApi));
      })
      .catch(console.error)
      .finally(() => setLoading(false));
  }, []);

  const handleSave = async () => {
    if (!editForm.title) return;
    const payload = toApi({ ...editForm, icon: editForm.icon || '📍' });

    try {
      if (isCreating) {
        const id = `evt-${Date.now()}`;
        const res = await fetch('/api/admin/timeline', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ ...payload, id }),
        });
        if (res.ok) {
          const created = fromApi(await res.json());
          setEvents(prev => [created, ...prev].sort((a, b) => b.year - a.year || (b.month || 0) - (a.month || 0)));
        }
      } else if (editingId) {
        const res = await fetch('/api/admin/timeline', {
          method: 'PUT',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ ...payload, id: editingId }),
        });
        if (res.ok) {
          const updated = fromApi(await res.json());
          setEvents(prev => prev.map(e => e.id === editingId ? updated : e).sort((a, b) => b.year - a.year || (b.month || 0) - (a.month || 0)));
        }
      }
      setEditingId(null);
      setIsCreating(false);
      setEditForm({});
      setSaveMsg('บันทึก Timeline เรียบร้อย!');
      setTimeout(() => setSaveMsg(''), 3000);
    } catch {
      setSaveMsg('เกิดข้อผิดพลาด กรุณาลองใหม่');
      setTimeout(() => setSaveMsg(''), 3000);
    }
  };

  const handleDelete = async (id: string) => {
    if (!confirm('ยืนยันที่จะลบเหตุการณ์นี้?')) return;
    const res = await fetch(`/api/admin/timeline?id=${id}`, { method: 'DELETE' });
    if (res.ok) setEvents(prev => prev.filter(evt => evt.id !== id));
  };

  const renderForm = () => (
    <div className="bg-[var(--color-surface)] border border-[var(--color-border)] rounded-xl p-6 mb-6 mt-4 relative">
      <h3 className="text-lg font-normal mb-4">{isCreating ? '✨ เพิ่มเหตุการณ์ใหม่' : '✏️ แก้ไขเหตุการณ์'}</h3>
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        
        <div className="space-y-1">
          <label className="text-xs text-[var(--color-muted)]">หมวดหมู่ (Category)</label>
          <select
            className="w-full bg-black/40 border border-white/10 rounded-lg px-3 py-2 text-sm text-[var(--color-text-primary)]"
            value={editForm.category || 'milestone'}
            onChange={e => setEditForm({ ...editForm, category: e.target.value as unknown })}
          >
            <option value="milestone">📍 Milestone</option>
            <option value="debut">🌟 Debut</option>
            <option value="work">🎬 Work</option>
            <option value="event">🎉 Event</option>
            <option value="award">🏆 Award</option>
          </select>
        </div>

        <div className="space-y-1">
          <label className="text-xs text-[var(--color-muted)]">ไอคอน (Icon - Emoji)</label>
          <input
            type="text"
            className="w-full bg-black/40 border border-white/10 rounded-lg px-3 py-2 text-sm text-[var(--color-text-primary)]"
            value={editForm.icon || ''}
            onChange={e => setEditForm({ ...editForm, icon: e.target.value })}
            placeholder="เช่น 🎬, 🏆, ✨"
          />
        </div>

        <div className="grid grid-cols-2 gap-4">
          <div className="space-y-1">
            <label className="text-xs text-[var(--color-muted)]">ปี (Year)</label>
            <input
              type="number"
              className="w-full bg-black/40 border border-white/10 rounded-lg px-3 py-2 text-sm text-[var(--color-text-primary)]"
              value={editForm.year || new Date().getFullYear()}
              onChange={e => setEditForm({ ...editForm, year: parseInt(e.target.value) })}
            />
          </div>
          <div className="space-y-1">
            <label className="text-xs text-[var(--color-muted)]">เดือน (Month - Optional)</label>
            <input
              type="number"
              min="1" max="12"
              className="w-full bg-black/40 border border-white/10 rounded-lg px-3 py-2 text-sm text-[var(--color-text-primary)]"
              value={editForm.month || ''}
              onChange={e => setEditForm({ ...editForm, month: e.target.value ? parseInt(e.target.value) : undefined })}
              placeholder="1-12"
            />
          </div>
        </div>

        <div className="space-y-1">
          <label className="text-xs text-[var(--color-muted)]">ศิลปิน (Actor)</label>
          <select
            className="w-full bg-black/40 border border-white/10 rounded-lg px-3 py-2 text-sm text-[var(--color-text-primary)]"
            value={editForm.actor || 'both'}
            onChange={e => setEditForm({ ...editForm, actor: e.target.value as unknown })}
          >
            <option value="both">Both (ทั้งคู่)</option>
            <option value="namtan">Namtan</option>
            <option value="film">Film</option>
          </select>
        </div>

        <div className="space-y-1">
          <label className="text-xs text-[var(--color-muted)]">Title (EN)</label>
          <input
            type="text"
            className="w-full bg-black/40 border border-white/10 rounded-lg px-3 py-2 text-sm text-[var(--color-text-primary)]"
            value={editForm.title || ''}
            onChange={e => setEditForm({ ...editForm, title: e.target.value })}
          />
        </div>

        <div className="space-y-1">
          <label className="text-xs text-[var(--color-muted)]">Title (TH)</label>
          <input
            type="text"
            className="w-full bg-black/40 border border-white/10 rounded-lg px-3 py-2 text-sm text-[var(--color-text-primary)]"
            value={editForm.titleThai || ''}
            onChange={e => setEditForm({ ...editForm, titleThai: e.target.value })}
          />
        </div>

        <div className="space-y-1 md:col-span-2">
          <label className="text-xs text-[var(--color-muted)]">Description (EN หรือ TH ก็ได้)</label>
          <textarea
            className="w-full bg-black/40 border border-white/10 rounded-lg px-3 py-2 text-sm text-[var(--color-text-primary)] min-h-[60px]"
            value={editForm.description || ''}
            onChange={e => setEditForm({ ...editForm, description: e.target.value })}
          />
        </div>

        <div className="space-y-1 md:col-span-2">
          <label className="text-xs text-[var(--color-muted)]">Image URL (Optional)</label>
          <input
            type="text"
            className="w-full bg-black/40 border border-white/10 rounded-lg px-3 py-2 text-sm text-[var(--color-text-primary)]"
            value={editForm.image || ''}
            onChange={e => setEditForm({ ...editForm, image: e.target.value })}
            placeholder="https://images.unsplash.com/..."
          />
        </div>

      </div>
      
      <div className="flex justify-end gap-2 mt-6 pt-4 border-t border-[var(--color-border)]">
        <button
          onClick={() => { setIsCreating(false); setEditingId(null); }}
          className="px-4 py-2 text-sm text-[var(--color-text-muted)] hover:text-[var(--color-text-primary)] transition-colors"
        >
          ยกเลิก
        </button>
        <button
          onClick={handleSave}
          className="px-4 py-2 text-sm bg-[#6cbfd0] hover:bg-[#4a9aab] text-white rounded-lg transition-colors font-medium"
        >
          💾 บันทึกเหตุการณ์
        </button>
      </div>
    </div>
  );

  return (
    <div className="max-w-4xl mx-auto px-6 py-8">
      {/* Header */}
      <div className="flex flex-col md:flex-row md:items-center justify-between mb-8 pb-4 border-b border-[var(--color-border)] gap-4">
        <div className="flex flex-col gap-1">
          <Link href="/admin/dashboard" className="text-sm font-medium text-[var(--color-text-secondary)] hover:text-[var(--color-text-primary)] transition-colors flex items-center gap-2 w-fit">
            <span>←</span> Back to Dashboard
          </Link>
          <h1 className="font-display text-2xl font-normal text-[var(--color-text-primary)]">📖 จัดการ Timeline (Timeline Editor)</h1>
          <p className="text-sm text-[var(--color-text-muted)]">เพิ่ม/แก้ไขประวัติการเดินทางของศิลปิน</p>
        </div>
        {!isCreating && !editingId && (
          <button
            onClick={() => { setIsCreating(true); setEditForm({ category: 'milestone', actor: 'both', year: new Date().getFullYear(), icon: '📍' }); }}
            className="px-4 py-2 bg-[#6cbfd0] text-[#141413] rounded-xl text-sm font-medium shadow-md transition-transform hover:scale-105"
          >
            + เพิ่มเหตุการณ์ใหม่
          </button>
        )}
      </div>

      {saveMsg && (
        <div className="mb-6 px-4 py-3 bg-green-500/10 border border-green-500/30 rounded-xl text-green-600 text-sm">
          ✅ {saveMsg}
        </div>
      )}

      {(isCreating || editingId) && renderForm()}

      {/* Timeline List */}
      <div className="border border-[var(--color-border)] rounded-xl overflow-hidden bg-[var(--color-surface)]">
         {events.length === 0 ? (
             <div className="p-8 text-center text-[var(--color-text-muted)]">ยังไม่มีเหตุการณ์ใน Timeline</div>
         ) : (
            <div className="divide-y divide-[var(--color-border)]">
              {events.map((evt) => (
                <div key={evt.id} className="p-4 flex items-center gap-4 hover:bg-[var(--color-panel)] transition-colors group">
                   <div className="w-16 shrink-0 text-center">
                      <div className="text-xl font-display mb-1">
                         {evt.icon}
                      </div>
                      <div className="text-[10px] text-[var(--color-text-muted)] tracking-wider">{evt.year}{evt.month ? `/${evt.month}` : ''}</div>
                   </div>
                   
                   <div className="flex-1 min-w-0">
                      <div className="flex items-center gap-2 mb-0.5">
                         <h4 className="font-normal text-[var(--color-text-primary)] truncate">{evt.titleThai} / {evt.title}</h4>
                         <span className={`text-[9px] px-1.5 py-0.5 rounded-sm uppercase tracking-wider ${
                            evt.actor === 'both' ? 'bg-[#6cbfd0]/20 text-[#6cbfd0]' : 
                            evt.actor === 'namtan' ? 'bg-[var(--namtan-teal)]/20 text-[var(--namtan-teal)]' : 
                            'bg-amber-500/20 text-amber-500'
                         }`}>
                           {evt.actor}
                         </span>
                      </div>
                      <p className="text-xs text-[var(--color-text-secondary)] line-clamp-1 mt-0.5">{evt.description}</p>
                   </div>
                   
                   <div className="flex opacity-0 group-hover:opacity-100 transition-opacity gap-2 shrink-0">
                      <button onClick={() => { setEditingId(evt.id); setEditForm(evt); setIsCreating(false); }} className="px-3 py-1.5 bg-white/5 border border-[var(--color-border)] rounded-lg text-xs hover:bg-[#6cbfd0]/20 hover:text-[#6cbfd0] transition-colors">
                         แก้ไข
                      </button>
                      <button onClick={() => handleDelete(evt.id)} className="px-3 py-1.5 bg-red-500/10 text-red-500 rounded-lg text-xs hover:bg-red-500/20 transition-colors">
                         ลบ
                      </button>
                   </div>
                </div>
              ))}
            </div>
         )}
      </div>
    </div>
  );
}

'use client';

import { useEffect, useState, useCallback } from 'react';
import Link from 'next/link';
import { useAuth } from '@/context/AuthContext';

interface UserItem {
  id: string;
  email: string;
  username: string | null;
  display_name: string;
  avatar_url: string | null;
  role: string;
  points: number;
  level: number;
  badges: string[];
  created_at: string;
}

interface RoleCounts {
  total: number;
  admin: number;
  moderator: number;
  fan: number;
  banned: number;
}

const ROLE_CONFIG: Record<string, { label: string; color: string; icon: string }> = {
  admin:     { label: 'Admin',     color: '#EF4444', icon: '👑' },
  moderator: { label: 'Moderator', color: '#8B5CF6', icon: '🛡️' },
  fan:       { label: 'Fan',       color: '#6cbfd0', icon: '💙' },
  banned:    { label: 'Banned',    color: '#6B7280', icon: '🚫' },
};

export default function UserManagementPage() {
  const { isSuperAdmin, loading: authLoading } = useAuth();
  const [users, setUsers] = useState<UserItem[]>([]);
  const [roleCounts, setRoleCounts] = useState<RoleCounts>({ total: 0, admin: 0, moderator: 0, fan: 0, banned: 0 });
  const [search, setSearch] = useState('');
  const [roleFilter, setRoleFilter] = useState('all');
  const [page, setPage] = useState(1);
  const [totalPages, setTotalPages] = useState(1);
  const [loading, setLoading] = useState(true);
  const [editingUser, setEditingUser] = useState<UserItem | null>(null);
  const [showBanConfirm, setShowBanConfirm] = useState<UserItem | null>(null);
  const [showDeleteConfirm, setShowDeleteConfirm] = useState<UserItem | null>(null);

  const fetchUsers = useCallback(async () => {
    if (!isSuperAdmin) return;
    setLoading(true);
    try {
      const params = new URLSearchParams({
        page: String(page),
        limit: '20',
        ...(search ? { search } : {}),
        ...(roleFilter !== 'all' ? { role: roleFilter } : {}),
      });
      const res = await fetch(`/api/admin/users?${params}`);
      if (res.ok) {
        const data = await res.json();
        setUsers(data.users || []);
        setTotalPages(data.totalPages || 1);
        setRoleCounts(data.roleCounts || { total: 0, admin: 0, moderator: 0, fan: 0, banned: 0 });
      }
    } catch (err) {
      console.error('Failed to fetch users:', err);
    }
    setLoading(false);
  }, [page, search, roleFilter, isSuperAdmin]);

  useEffect(() => { fetchUsers(); }, [fetchUsers]);

  // Debounced search
  const [searchInput, setSearchInput] = useState('');
  useEffect(() => {
    const timer = setTimeout(() => {
      setSearch(searchInput);
      setPage(1);
    }, 400);
    return () => clearTimeout(timer);
  }, [searchInput]);

  const handleRoleChange = async (userId: string, newRole: string) => {
    await fetch('/api/admin/users', {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ id: userId, role: newRole }),
    });
    setEditingUser(null);
    fetchUsers();
  };

  const handlePointsChange = async (userId: string, points: number) => {
    await fetch('/api/admin/users', {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ id: userId, points }),
    });
    fetchUsers();
  };

  const handlePasswordChange = async (userId: string, password: string) => {
    const res = await fetch('/api/admin/users', {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ id: userId, password }),
    });
    if (!res.ok) {
      const err = await res.json();
      alert(`เปลี่ยนรหัสผ่านไม่สำเร็จ: ${err.error}`);
    } else {
      alert('เปลี่ยนรหัสผ่านสำเร็จ!');
    }
  };

  const handleBan = async (userId: string) => {
    await fetch(`/api/admin/users?id=${userId}`, { method: 'DELETE' });
    setShowBanConfirm(null);
    fetchUsers();
  };

  const handleDelete = async (userId: string) => {
    await fetch(`/api/admin/users?id=${userId}&hard=true`, { method: 'DELETE' });
    setShowDeleteConfirm(null);
    fetchUsers();
  };

  const handleUnban = async (userId: string) => {
    await fetch('/api/admin/users', {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ id: userId, role: 'fan' }),
    });
    fetchUsers();
  };

  if (authLoading) {
    return <div className="text-center py-20 animate-pulse text-[var(--color-text-secondary)]">กำลังตรวจสอบสิทธิ์...</div>;
  }

  if (!isSuperAdmin) {
    return (
      <div className="max-w-2xl mx-auto px-6 py-20 text-center">
        <div className="w-16 h-16 mx-auto mb-6 bg-red-500/10 rounded-full flex items-center justify-center">
          <span className="text-3xl">🔒</span>
        </div>
        <h1 className="font-display text-2xl font-light mb-2">Access Denied</h1>
        <p className="text-[var(--color-text-secondary)] mb-8">คุณต้องมีสิทธิ์ Admin เท่านั้นจึงจะสามารถจัดการผู้ใช้ได้</p>
        <Link href="/admin/dashboard" className="px-6 py-3 bg-[var(--color-panel)] hover:bg-[var(--color-border)] text-[var(--color-text-primary)] rounded-lg transition-colors">
          กลับไปที่ Dashboard
        </Link>
      </div>
    );
  }

  return (
    <div className="max-w-6xl mx-auto px-6 py-8">
      {/* Header */}
      <div className="flex items-center justify-between mb-6">
        <div className="flex items-center gap-4">
          <Link href="/admin/dashboard" className="text-[var(--color-text-secondary)] hover:text-[var(--color-text-primary)] text-sm transition-colors">
            ← Dashboard
          </Link>
          <h1 className="font-display text-xl font-normal">👥 จัดการผู้ใช้</h1>
        </div>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-2 md:grid-cols-5 gap-3 mb-6">
        <StatCard label="ทั้งหมด" value={roleCounts.total} color="#6cbfd0" icon="👥" />
        <StatCard label="Admin" value={roleCounts.admin} color="#EF4444" icon="👑" />
        <StatCard label="Moderator" value={roleCounts.moderator} color="#8B5CF6" icon="🛡️" />
        <StatCard label="Fan" value={roleCounts.fan} color="#3B82F6" icon="💙" />
        <StatCard label="Banned" value={roleCounts.banned} color="#6B7280" icon="🚫" />
      </div>

      {/* Search & Filter */}
      <div className="flex gap-3 mb-6 flex-wrap">
        <div className="flex-1 min-w-[200px]">
          <input
            type="text"
            value={searchInput}
            onChange={(e) => setSearchInput(e.target.value)}
            placeholder="🔍 ค้นหาชื่อ, อีเมล, username..."
            className="w-full bg-[var(--color-panel)] border border-[var(--color-border)] text-[var(--color-text-primary)] rounded-xl px-4 py-2.5 focus:border-[var(--namtan-teal)] focus:ring-1 focus:ring-[var(--namtan-teal)] focus:outline-none transition-all text-sm"
          />
        </div>
        <div className="flex gap-2">
          <FilterBtn active={roleFilter === 'all'} onClick={() => { setRoleFilter('all'); setPage(1); }}>
            ทั้งหมด
          </FilterBtn>
          {Object.entries(ROLE_CONFIG).map(([key, cfg]) => (
            <FilterBtn key={key} active={roleFilter === key} onClick={() => { setRoleFilter(key); setPage(1); }}>
              {cfg.icon} {cfg.label}
            </FilterBtn>
          ))}
        </div>
      </div>

      {/* User List */}
      {loading ? (
        <div className="text-center text-[var(--color-text-secondary)] py-12">กำลังโหลด...</div>
      ) : users.length === 0 ? (
        <div className="text-center text-[var(--color-text-secondary)] py-12">ไม่พบผู้ใช้</div>
      ) : (
        <div className="space-y-2">
          {users.map((user) => {
            const roleInfo = ROLE_CONFIG[user.role] || ROLE_CONFIG.fan;
            const joinDate = new Date(user.created_at).toLocaleDateString('th-TH', {
              year: 'numeric', month: 'short', day: 'numeric',
            });

            return (
              <div
                key={user.id}
                className={`flex items-center gap-4 p-4 bg-[var(--color-surface)] rounded-lg border border-[var(--color-border)] hover:border-[var(--color-border)] transition-colors ${
                  user.role === 'banned' ? 'opacity-50' : ''
                }`}
              >
                {/* Avatar */}
                <div className="w-10 h-10 rounded-full bg-gradient-to-br from-[#6cbfd0] to-[#fbdf74] flex items-center justify-center text-[var(--color-text-primary)] text-sm font-medium overflow-hidden shrink-0">
                  {user.avatar_url ? (
                    <img src={user.avatar_url} alt="" className="w-full h-full object-cover" />
                  ) : (
                    (user.display_name || '?')[0].toUpperCase()
                  )}
                </div>

                {/* User Info */}
                <div className="flex-1 min-w-0">
                  <div className="flex items-center gap-2 flex-wrap">
                    <span className="text-sm font-medium text-[var(--color-text-primary)] truncate">
                      {user.display_name || 'User'}
                    </span>
                    <span
                      className="text-xs px-2 py-0.5 rounded-full"
                      style={{
                        backgroundColor: roleInfo.color + '20',
                        color: roleInfo.color,
                      }}
                    >
                      {roleInfo.icon} {roleInfo.label}
                    </span>
                  </div>
                  <div className="flex items-center gap-3 mt-0.5">
                    <span className="text-xs text-[var(--color-text-secondary)] truncate">{user.email}</span>
                    <span className="text-xs text-[#fbdf74]">⭐ {user.points} pts</span>
                    <span className="text-xs text-[var(--color-text-secondary)]">Lv.{user.level}</span>
                    <span className="text-xs text-[var(--color-text-muted)]">เข้าร่วม {joinDate}</span>
                  </div>
                </div>

                {/* Actions */}
                <div className="flex gap-2 shrink-0">
                  {user.role === 'banned' ? (
                    <button
                      onClick={() => handleUnban(user.id)}
                      className="px-3 py-1.5 bg-green-500/10 hover:bg-green-500/20 text-green-400 rounded-lg text-xs transition-colors"
                    >
                      ✅ ปลดแบน
                    </button>
                  ) : (
                    <>
                      <button
                        onClick={() => setEditingUser(user)}
                        className="px-3 py-1.5 bg-[var(--color-panel)] hover:bg-[var(--color-border)] rounded-lg text-xs text-[#b0aea5] transition-colors"
                      >
                        ✏️ แก้ไข
                      </button>
                      <button
                        onClick={() => setShowBanConfirm(user)}
                        className="px-3 py-1.5 bg-orange-500/10 hover:bg-orange-500/20 text-orange-400 rounded-lg text-xs transition-colors"
                      >
                        🚫 แบน
                      </button>
                    </>
                  )}
                  <button
                    onClick={() => setShowDeleteConfirm(user)}
                    className="px-3 py-1.5 bg-red-500/10 hover:bg-red-500/20 text-red-400 rounded-lg text-xs transition-colors"
                  >
                    🗑️ ลบ
                  </button>
                </div>
              </div>
            );
          })}
        </div>
      )}

      {/* Pagination */}
      {totalPages > 1 && (
        <div className="flex items-center justify-center gap-2 mt-6">
          <button
            onClick={() => setPage((p) => Math.max(1, p - 1))}
            disabled={page === 1}
            className="px-3 py-1.5 bg-[var(--color-panel)] hover:bg-[var(--color-border)] disabled:opacity-30 rounded-lg text-sm transition-colors"
          >
            ← ก่อนหน้า
          </button>
          <span className="text-sm text-[var(--color-text-secondary)] px-3">
            หน้า {page} / {totalPages}
          </span>
          <button
            onClick={() => setPage((p) => Math.min(totalPages, p + 1))}
            disabled={page === totalPages}
            className="px-3 py-1.5 bg-[var(--color-panel)] hover:bg-[var(--color-border)] disabled:opacity-30 rounded-lg text-sm transition-colors"
          >
            ถัดไป →
          </button>
        </div>
      )}

      {/* Edit User Modal */}
      {editingUser && (
        <EditUserModal
          user={editingUser}
          onClose={() => setEditingUser(null)}
          onRoleChange={handleRoleChange}
          onPointsChange={handlePointsChange}
          onPasswordChange={handlePasswordChange}
        />
      )}

      {/* Ban Confirmation Modal */}
      {showBanConfirm && (
        <BanConfirmModal
          user={showBanConfirm}
          onClose={() => setShowBanConfirm(null)}
          onConfirm={() => handleBan(showBanConfirm.id)}
        />
      )}

      {/* Delete Confirmation Modal */}
      {showDeleteConfirm && (
        <DeleteConfirmModal
          user={showDeleteConfirm}
          onClose={() => setShowDeleteConfirm(null)}
          onConfirm={() => handleDelete(showDeleteConfirm.id)}
        />
      )}
    </div>
  );
}

// ── Stat Card ──
function StatCard({ label, value, color, icon }: { label: string; value: number; color: string; icon: string }) {
  return (
    <div className="bg-[var(--color-surface)] rounded-xl p-4 border border-[var(--color-border)]">
      <div className="flex items-center gap-2">
        <span className="text-lg">{icon}</span>
        <div className="text-2xl font-light" style={{ color }}>{value}</div>
      </div>
      <div className="text-xs text-[var(--color-text-secondary)] mt-1">{label}</div>
    </div>
  );
}

// ── Filter Button ──
function FilterBtn({ active, onClick, children }: { active: boolean; onClick: () => void; children: React.ReactNode }) {
  return (
    <button
      onClick={onClick}
      className={`px-3 py-1.5 rounded-full text-xs transition-colors whitespace-nowrap ${
        active ? 'bg-[#6cbfd0] text-[#141413]' : 'bg-[var(--color-panel)] text-[var(--color-text-muted)] hover:text-[var(--color-text-primary)]'
      }`}
    >
      {children}
    </button>
  );
}

// ── Edit User Modal ──
function EditUserModal({
  user,
  onClose,
  onRoleChange,
  onPointsChange,
  onPasswordChange,
}: {
  user: UserItem;
  onClose: () => void;
  onRoleChange: (userId: string, role: string) => void;
  onPointsChange: (userId: string, points: number) => void;
  onPasswordChange: (userId: string, password: string) => void;
}) {
  const [role, setRole] = useState(user.role);
  const [points, setPoints] = useState(user.points);
  const [password, setPassword] = useState('');
  const [saving, setSaving] = useState(false);

  const handleSave = async () => {
    setSaving(true);
    if (role !== user.role) {
      await onRoleChange(user.id, role);
    }
    if (points !== user.points) {
      await onPointsChange(user.id, points);
    }
    if (password.trim().length >= 6) {
      await onPasswordChange(user.id, password);
    } else if (password && password.trim().length < 6) {
      alert('รหัสผ่านต้องมีอย่างน้อย 6 ตัวอักษร');
      setSaving(false);
      return;
    }
    setSaving(false);
    onClose();
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4" onClick={onClose}>
      <div
        onClick={(e) => e.stopPropagation()}
        className="w-full max-w-md bg-[var(--color-surface)] rounded-xl border border-[var(--color-border)] p-6"
      >
        {/* User header */}
        <div className="flex items-center gap-3 mb-6">
          <div className="w-12 h-12 rounded-full bg-gradient-to-br from-[#6cbfd0] to-[#fbdf74] flex items-center justify-center text-[var(--color-text-primary)] text-lg font-medium overflow-hidden">
            {user.avatar_url ? (
              <img src={user.avatar_url} alt="" className="w-full h-full object-cover" />
            ) : (
              (user.display_name || '?')[0].toUpperCase()
            )}
          </div>
          <div>
            <h2 className="font-display text-lg font-normal">{user.display_name}</h2>
            <p className="text-xs text-[var(--color-text-secondary)]">{user.email}</p>
          </div>
        </div>

        {/* Role selection */}
        <div className="mb-4">
          <label className="block text-xs text-[var(--color-text-secondary)] mb-2">Role</label>
          <div className="grid grid-cols-2 gap-2">
            {Object.entries(ROLE_CONFIG).filter(([k]) => k !== 'banned').map(([key, cfg]) => (
              <button
                key={key}
                onClick={() => setRole(key)}
                className={`flex items-center gap-2 px-4 py-3 rounded-lg border text-sm transition-all ${
                  role === key
                    ? 'border-[#6cbfd0] bg-[#6cbfd0]/10 text-[var(--color-text-primary)]'
                    : 'border-[var(--color-border)] bg-[var(--color-surface)] text-[var(--color-text-muted)] hover:text-[var(--color-text-primary)] hover:border-[var(--color-border)]'
                }`}
              >
                <span>{cfg.icon}</span>
                <span>{cfg.label}</span>
              </button>
            ))}
          </div>
        </div>

        {/* Points */}
        <div className="mb-6">
          <label className="block text-xs text-[var(--color-text-secondary)] mb-2">Points</label>
          <div className="flex items-center gap-2">
            <button
              onClick={() => setPoints(Math.max(0, points - 50))}
              className="px-3 py-2 bg-[var(--color-panel)] hover:bg-[var(--color-border)] rounded-lg text-sm transition-colors"
            >
              -50
            </button>
            <input
              type="number"
              value={points}
              onChange={(e) => setPoints(Math.max(0, Number(e.target.value)))}
              className="flex-1 px-3 py-2 bg-[var(--color-panel)] border border-[var(--color-border)] rounded-lg text-[var(--color-text-primary)] text-center text-sm focus:outline-none focus:border-[#6cbfd0]"
            />
            <button
              onClick={() => setPoints(points + 50)}
              className="px-3 py-2 bg-[var(--color-panel)] hover:bg-[var(--color-border)] rounded-lg text-sm transition-colors"
            >
              +50
            </button>
            <button
              onClick={() => setPoints(points + 100)}
              className="px-3 py-2 bg-[var(--color-panel)] hover:bg-[var(--color-border)] rounded-lg text-sm transition-colors"
            >
              +100
            </button>
          </div>
        </div>

        {/* Password Reset */}
        <div className="mb-6">
          <label className="block text-xs text-[var(--color-text-secondary)] mb-2">เปลี่ยนรหัสผ่าน (ทิ้งว่างไว้ถ้าไม่ต้องการเปลี่ยน)</label>
          <input
            type="text"
            placeholder="รหัสผ่านใหม่ (อย่างน้อย 6 ตัวอักษร)"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
            className="w-full px-3 py-2 bg-[var(--color-panel)] border border-[var(--color-border)] rounded-lg text-[var(--color-text-primary)] text-sm focus:outline-none focus:border-red-500"
          />
        </div>

        {/* Buttons */}
        <div className="flex gap-3">
          <button
            onClick={onClose}
            className="flex-1 py-2.5 bg-[var(--color-panel)] text-[var(--color-text-muted)] rounded-lg hover:bg-[var(--color-border)] transition-colors text-sm"
          >
            ยกเลิก
          </button>
          <button
            onClick={handleSave}
            disabled={saving}
            className="flex-1 py-2.5 bg-[#6cbfd0] text-[#141413] rounded-lg hover:bg-[#4a9aab] disabled:opacity-50 transition-colors text-sm"
          >
            {saving ? 'กำลังบันทึก...' : 'บันทึก'}
          </button>
        </div>
      </div>
    </div>
  );
}

// ── Ban Confirmation Modal ──
function BanConfirmModal({
  user,
  onClose,
  onConfirm,
}: {
  user: UserItem;
  onClose: () => void;
  onConfirm: () => void;
}) {
  const [confirming, setConfirming] = useState(false);

  const handleConfirm = async () => {
    setConfirming(true);
    await onConfirm();
    setConfirming(false);
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-4" onClick={onClose}>
      <div
        onClick={(e) => e.stopPropagation()}
        className="w-full max-w-sm bg-[var(--color-surface)] rounded-xl border border-orange-500/30 p-6 text-center"
      >
        <div className="w-16 h-16 mx-auto mb-4 rounded-full bg-orange-500/10 flex items-center justify-center">
          <span className="text-3xl">🚫</span>
        </div>

        <h2 className="font-display text-lg font-normal mb-2">แบนผู้ใช้</h2>
        <p className="text-sm text-[var(--color-text-muted)] mb-1">
          ต้องการแบน <strong className="text-[var(--color-text-primary)]">{user.display_name}</strong>?
        </p>
        <p className="text-xs text-[var(--color-text-muted)] mb-6">
          ผู้ใช้จะไม่สามารถโพสต์หรือแสดงความเห็นได้ คุณสามารถปลดแบนได้ภายหลัง
        </p>

        <div className="flex gap-3">
          <button
            onClick={onClose}
            className="flex-1 py-2.5 bg-[var(--color-panel)] text-[var(--color-text-muted)] rounded-lg hover:bg-[var(--color-border)] transition-colors text-sm"
          >
            ยกเลิก
          </button>
          <button
            onClick={handleConfirm}
            disabled={confirming}
            className="flex-1 py-2.5 bg-orange-500 text-[var(--color-text-primary)] rounded-lg hover:bg-orange-600 disabled:opacity-50 transition-colors text-sm"
          >
