export async function DELETE(req: NextRequest) {
  if (!(await verifyAdmin(req))) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });

  const id = req.nextUrl.searchParams.get('id');
  if (!id) return NextResponse.json({ error: 'Missing id' }, { status: 400 });

  const supabase = getAdminClient();

  // Fetch brand link before delete so we can re-sync after
  const { data: before } = await supabase
    .from('media_posts')
    .select('brand_collab_id')
    .eq('id', id)
    .single();

  const { error } = await supabase.from('media_posts').delete().eq('id', id);
  if (error) return NextResponse.json({ error: error.message }, { status: 500 });

  if (before?.brand_collab_id) {
    await syncBrandMediaItems(supabase, before.brand_collab_id as number);
  }

  return NextResponse.json({ success: true });
}

import { NextRequest, NextResponse } from 'next/server';
import { getAdminClient } from '@/lib/supabase';
import { cookies } from 'next/headers';
import * as jose from 'jose';

const JWT_SECRET = process.env.ADMIN_JWT_SECRET || 'namtanfilm-admin-secret-change-this-in-production';

async function checkAdminAuth(): Promise<boolean> {
  try {
    const token = (await cookies()).get('admin_session')?.value;
    if (!token) return false;
    const secret = new TextEncoder().encode(JWT_SECRET);
    await jose.jwtVerify(token, secret);
    return true;
  } catch {
    return false;
  }
}

// GET /api/admin/notifications — fetch recent broadcast history
export async function GET() {
  if (!(await checkAdminAuth())) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  try {
    const adminClient = getAdminClient();
    const { data, error } = await adminClient
      .from('user_notifications')
      .select('type, title, body, link, created_at')
      .order('created_at', { ascending: false })
      .limit(300);

    if (error) return NextResponse.json({ error: error.message }, { status: 500 });

    // Deduplicate broadcasts: same title sent within the same minute = 1 broadcast
    const seen = new Map<string, { count: number; type: string; title: string; body: string | null; link: string | null; created_at: string }>();
    for (const n of data ?? []) {
      const key = `${n.title}||${(n.created_at ?? '').substring(0, 16)}`;
      if (seen.has(key)) {
        seen.get(key)!.count++;
      } else {
        seen.set(key, { count: 1, type: n.type, title: n.title, body: n.body, link: n.link, created_at: n.created_at });
      }
    }

    return NextResponse.json([...seen.values()].slice(0, 30));
  } catch (error: unknown) {
    return NextResponse.json({ error: error.message }, { status: 500 });
  }
}

export async function POST(req: Request) {
  try {
    // 1. Verify admin auth
    const token = (await cookies()).get('admin_session')?.value;
    if (!token) return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    
    try {
      const secret = new TextEncoder().encode(JWT_SECRET);
      await jose.jwtVerify(token, secret);
    } catch {
      return NextResponse.json({ error: 'Invalid token' }, { status: 401 });
    }

    const { title, body, link, type } = await req.json();
    if (!title || !type) {
      return NextResponse.json({ error: 'Missing required fields' }, { status: 400 });
    }

    const adminClient = getAdminClient();

    // 2. Get all users
    const { data: users, error: usersErr } = await adminClient.from('users').select('id');
    
    if (usersErr) {
      console.warn("Could not load users table, broadcasting skipped.", usersErr);
      return NextResponse.json({ error: 'Failed to retrieve users' }, { status: 500 });
    }

    if (!users || users.length === 0) {
      return NextResponse.json({ message: 'No users found to notify' });
    }

    // 3. Prepare bulk insert
    const notifications = users.map(u => ({
      user_id: u.id,
      type,
      title,
      body,
      link,
      is_read: false
    }));

    // 4. Execute insert
    const { error: insertErr } = await adminClient.from('user_notifications').insert(notifications);
    if (insertErr) throw insertErr;

    return NextResponse.json({ success: true, count: users.length });

  } catch (error: unknown) {
    console.error('Broadcast Error:', error);
    return NextResponse.json({ error: error.message }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { getAdminClient, supabase } from '@/lib/supabase';
import { verifyAdmin } from '@/lib/auth';

// Cache GET for 5 minutes — settings change infrequently
export const revalidate = 300;

// GET /api/admin/settings — returns { general, features, social, maintenance }
export async function GET(req: NextRequest) {
  // Settings are public-readable
  const { data, error } = await supabase
    .from('site_settings')
    .select('key, value');

  if (error) return NextResponse.json({ error: error.message }, { status: 500 });

  const settings: Record<string, any> = {};
  for (const row of (data as unknown[]) ?? []) {
    settings[row.key] = row.value;
  }
  return NextResponse.json(settings);
}

// PUT /api/admin/settings — upsert one key at a time or all keys
// Body: { key: string, value: object } or { general: {}, features: {}, ... }
export async function PUT(req: NextRequest) {
  if (!(await verifyAdmin(req))) {
    return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
  }

  const body = await req.json();
  const admin = getAdminClient();

  // Support both single-key { key, value } and multi-key { general, features, ... }
  let rows: { key: string; value: unknown; updated_at: string }[] = [];

  if ('key' in body && 'value' in body) {
    rows = [{ key: body.key, value: body.value, updated_at: new Date().toISOString() }];
  } else {
    rows = Object.entries(body).map(([key, value]) => ({
      key,
      value,
      updated_at: new Date().toISOString(),
    }));
  }

  const { error } = await admin
    .from('site_settings')
    .upsert(rows, { onConflict: 'key' });

  if (error) return NextResponse.json({ error: error.message }, { status: 500 });
  return NextResponse.json({ success: true });
}

