// Stats-strip tile types — small stat tiles below the bento grid
export type StatsTileType =
  | 'nt_awards' | 'fl_awards'
  | 'nt_brands' | 'fl_brands'
  | 'nt_ig'     | 'fl_ig'
  | 'nt_x'      | 'fl_x'
