              {upcoming.map((event, i) => {
                const style = TYPE_STYLES[event.event_type] || { icon: '🗓', color: 'var(--namtan-teal)', label: event.event_type };
                const d = formatDate(event.date);

                return (
                  <motion.div
                    key={event.id}
                    initial={{ opacity: 0, y: 15 }}
                    whileInView={{ opacity: 1, y: 0 }}
                    viewport={{ once: true }}
