'use client';

import React, {
  createContext,
  useContext,
  useState,
  useCallback,
  useMemo,
  useEffect
} from 'react';
import { ViewState } from '@/types';
import { announceToScreenReader } from '@/lib/utils';
import { actors } from '@/data/actors';

interface ViewStateContextType {
  state: ViewState;
  setState: (state: ViewState) => void;
  transitionTo: (state: ViewState) => void;
  isTransitioning: boolean;
  hoveredActor: 'namtan' | 'film' | null;
  setHoveredActor: (actor: 'namtan' | 'film' | null) => void;
  reducedMotion: boolean;
}

export const ViewStateContext = createContext<ViewStateContextType | null>(null);

const announcements: Record<ViewState, string> = {
  both: `กำลังแสดงผลงานคู่ของ ${actors.namtan.nameThai} และ ${actors.film.nameThai}`,
  namtan: `กำลังแสดงผลงานของ ${actors.namtan.nameThai}`,
  film: `กำลังแสดงผลงานของ ${actors.film.nameThai}`,
  lunar: 'Lunar Space',
};

export function ViewStateProvider({
  children,
  initialState = 'both',
}: {
  children: React.ReactNode;
  initialState?: ViewState;
}) {
  const [state, setStateInternal] = useState<ViewState>(initialState);
  const [isTransitioning, setIsTransitioning] = useState(false);
  const [hoveredActor, setHoveredActor] = useState<'namtan' | 'film' | null>(null);
  const [reducedMotion, setReducedMotion] = useState(false);

  // Sync state if initialState changes via URL navigation
  useEffect(() => {
    setStateInternal(initialState);
  }, [initialState]);

  useEffect(() => {
    const mediaQuery = window.matchMedia('(prefers-reduced-motion: reduce)');
    setReducedMotion(mediaQuery.matches);

    const handler = (e: MediaQueryListEvent) => setReducedMotion(e.matches);
    mediaQuery.addEventListener('change', handler);
    return () => mediaQuery.removeEventListener('change', handler);
  }, []);

  const transitionTo = useCallback((newState: ViewState) => {
    if (state === newState || isTransitioning) return;

    setIsTransitioning(true);
    announceToScreenReader(announcements[newState]);

    const exitDelay = reducedMotion ? 0 : 150;
    const transitionDuration = reducedMotion ? 0 : 400;

    setTimeout(() => {
      setStateInternal(newState);
      setTimeout(() => setIsTransitioning(false), transitionDuration);
    }, exitDelay);
  }, [state, isTransitioning, reducedMotion]);

  const value = useMemo(() => ({
    state,
    setState: setStateInternal,
    transitionTo,
    isTransitioning,
    hoveredActor,
    setHoveredActor,
    reducedMotion,
  }), [state, transitionTo, isTransitioning, hoveredActor, reducedMotion]);

  return (
    <ViewStateContext.Provider value={value}>
      {children}
    </ViewStateContext.Provider>
  );
}

export function useViewState() {
  const context = useContext(ViewStateContext);
  if (!context) {
    throw new Error('useViewState must be used within ViewStateProvider');
  }
  return context;
}

/** Returns null when called outside a ViewStateProvider (safe for shared components). */
export function useViewStateSafe() {
  return useContext(ViewStateContext);
}

import nextVitals from 'eslint-config-next/core-web-vitals';
import nextTypescript from 'eslint-config-next/typescript';

export default [
  ...nextVitals,
  ...nextTypescript,
];

import { NextRequest } from 'next/server';
import { createServerClient, type CookieOptions } from '@supabase/ssr';
import { getAdminClient } from '@/lib/supabase';

const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL!;
const supabaseAnonKey = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!;

import { cookies } from 'next/headers';

/**
 * Creates a server-side Supabase client using @supabase/ssr
 * This correctly handles Supabase's chunked cookies.
 */
export async function createClient() {
  const cookieStore = await cookies();

  return createServerClient(
    supabaseUrl,
    supabaseAnonKey,
    {
      cookies: {
        getAll() {
          return cookieStore.getAll();
        },
        setAll(cookiesToSet) {
          try {
            cookiesToSet.forEach(({ name, value, options }) => {
              cookieStore.set(name, value, options);
            });
          } catch {
            // Ignored if called from a Server Component
          }
        },
      },
    }
  );
}

export async function getAuthUserRole(req?: NextRequest): Promise<string | null> {
  try {
    const supabase = await createClient();
    const { data: { user }, error } = await supabase.auth.getUser();

    if (error || !user) return null;

    const admin = getAdminClient();
    const { data: profile } = await admin
      .from('users')
      .select('role')
      .eq('id', user.id)
      .single();

    if (!profile) return null;
    return profile.role;
  } catch {
    return null;
  }
}

/**
 * Verify that the request is from an admin or moderator user.
 */
export async function verifyAdmin(req?: NextRequest): Promise<boolean> {
  try {
    const role = await getAuthUserRole(req);
    // Both admin and moderator have full access to general admin routes
    return role === 'admin' || role === 'moderator';
  } catch {
    return false;
  }
}

/**
 * Get the authenticated user's ID from the request.
 * Returns null if not authenticated.
 */
export async function getAuthUserId(req: NextRequest): Promise<string | null> {
  try {
    const supabase = await createClient();
    const { data: { user }, error } = await supabase.auth.getUser();

    if (error || !user) return null;

    return user.id;
  } catch {
    return null;
  }
}

import { Ratelimit } from '@upstash/ratelimit';
import { Redis } from '@upstash/redis/cloudflare';

// Initialize Redis if the environment variables are available
const redis = (process.env.UPSTASH_REDIS_REST_URL && process.env.UPSTASH_REDIS_REST_TOKEN)
  ? new Redis({
      url: process.env.UPSTASH_REDIS_REST_URL,
      token: process.env.UPSTASH_REDIS_REST_TOKEN,
    })
  : null;

/**
 * Fallback empty rate limiter if variables are missing
 */
const mockRateLimit = {
  limit: async (ip: string) => ({
    success: true,
    limit: 10,
    remaining: 9,
    reset: Date.now() + 10000,
  }),
};

/**
 * General API Limiter: 50 requests per 10 seconds per IP.
 * Used for standard API endpoints like /api/analytics
 */
export const rateLimitAPI = redis
  ? new Ratelimit({
      redis: redis,
      limiter: Ratelimit.slidingWindow(50, '10 s'),
      analytics: true,
      prefix: '@upstash/ratelimit/api',
    })
  : mockRateLimit;

/**
 * Authentication Limiter: Strict limit of 5 requests per 10 seconds.
 * Used for /login, /register, and sensitive auth routes to prevent brute-force attacks.
 */
export const rateLimitAuth = redis
  ? new Ratelimit({
      redis: redis,
      limiter: Ratelimit.slidingWindow(5, '10 s'),
      analytics: true,
      prefix: '@upstash/ratelimit/auth',
    })
  : mockRateLimit;

import { NextResponse } from 'next/server';
import type { NextRequest } from 'next/server';
import { rateLimitAPI, rateLimitAuth } from '@/lib/ratelimit';
import createIntlMiddleware from 'next-intl/middleware';
import { routing } from './i18n/routing';

const intlMiddleware = createIntlMiddleware(routing);

// Routes to apply rate limiting depending on strictness
const API_ROUTES_PREFIX = '/api/';
const AUTH_ROUTES = ['/login', '/register', '/api/auth'];

// In-memory cache for maintenance flag (refresh every 5 min)
// Querying Supabase REST directly avoids an internal HTTP round-trip through Next.js routing
const SUPABASE_URL = process.env.NEXT_PUBLIC_SUPABASE_URL ?? '';
const SUPABASE_ANON_KEY = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY ?? '';
let maintenanceCached: { enabled: boolean; message: string } | null = null;
let maintenanceCacheExpiry = 0;

async function getMaintenanceSettings(): Promise<{ enabled: boolean; message: string }> {
  const now = Date.now();
  if (maintenanceCached && now < maintenanceCacheExpiry) return maintenanceCached;
  try {
    const res = await fetch(
      `${SUPABASE_URL}/rest/v1/site_settings?select=key,value&key=eq.maintenance`,
      {
        headers: {
          apikey: SUPABASE_ANON_KEY,
          Authorization: `Bearer ${SUPABASE_ANON_KEY}`,
        },
        next: { revalidate: 300 },
      }
    );
    if (res.ok) {
      const rows: { key: string; value: Record<string, any> }[] = await res.json();
      const value = rows?.[0]?.value ?? {};
      maintenanceCached = {
        enabled: value.enabled ?? false,
        message: value.message ?? 'เว็บไซต์กำลังปรับปรุง กรุณากลับมาใหม่ภายหลัง',
      };
      maintenanceCacheExpiry = now + 300_000;
      return maintenanceCached;
    }
  } catch {}
  return { enabled: false, message: '' };
}

export async function middleware(request: NextRequest) {
  const path = request.nextUrl.pathname;

  // Only apply rate limiting to specific sensitive routes
  const isApiRoute = path.startsWith(API_ROUTES_PREFIX);
  const isAuthRoute = AUTH_ROUTES.some((route) => path.startsWith(route));
  const isAdminRoute = path.startsWith('/admin');

  // Determine IP
  const ip = request.headers.get('x-forwarded-for')?.split(',')[0].trim() || request.headers.get('x-real-ip') || '127.0.0.1';

  if (isAuthRoute) {
    // 1. Strict Limiter for Auth Routes
    const { success, limit, remaining } = await rateLimitAuth.limit(`auth_${ip}`);

    if (!success) {
      if (path.startsWith('/api/')) {
        return NextResponse.json(
          { error: 'Too Many Requests', message: 'You have exceeded the allowed limit for authentication attempts. Please try again later.' },
          { status: 429, headers: { 'X-RateLimit-Limit': limit.toString(), 'X-RateLimit-Remaining': remaining.toString() } }
        );
      }
      return new NextResponse(
        `Too Many Requests. You are being rate limited. Please try again later.`,
        { status: 429, headers: { 'Content-Type': 'text/plain' } }
      );
    }
  } else if (isApiRoute) {
    // 2. Moderate Limiter for Standard API Routes
    const { success, limit, remaining } = await rateLimitAPI.limit(`api_${ip}`);

    if (!success) {
      return NextResponse.json(
        { error: 'Too Many Requests', message: 'API rate limit exceeded.' },
        { status: 429, headers: { 'X-RateLimit-Limit': limit.toString(), 'X-RateLimit-Remaining': remaining.toString() } }
      );
    }
  }

  // Skip i18n + maintenance check for /admin and /api
  if (isAdminRoute || isApiRoute || path.startsWith('/auth/callback')) {
    return NextResponse.next();
  }

  // ── Maintenance Mode ──────────────────────────────────────────────────────
  // Only check for non-admin, non-api page routes
  if (!isAdminRoute && !isApiRoute) {
    const { enabled, message } = await getMaintenanceSettings();
    if (enabled) {
      // Allow /auth pages so admins can still log in
      const isAuthPage = path.includes('/auth/');
      if (!isAuthPage) {
        return new NextResponse(
          `<!doctype html><html lang="th"><head><meta charset="utf-8"><title>กำลังปรับปรุง</title>
          <meta name="viewport" content="width=device-width,initial-scale=1">
          <style>body{font-family:sans-serif;display:flex;align-items:center;justify-content:center;min-height:100vh;margin:0;background:#141413;color:#faf9f5;}
          .box{text-align:center;padding:2rem;max-width:400px;}h1{font-size:2rem;margin-bottom:1rem;}p{color:#87867f;}</style>
          </head><body><div class="box"><div style="font-size:3rem;margin-bottom:1rem">🔧</div>
          <h1>กำลังปรับปรุง</h1><p>${message}</p></div></body></html>`,
          { status: 503, headers: { 'Content-Type': 'text/html; charset=utf-8', 'Retry-After': '3600' } }
        );
      }
    }
  }

  return intlMiddleware(request);
}

